                                <th className="p-4 text-xs font-semibold text-white/50 uppercase tracking-wider text-center">Allocation</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-white/5 text-sm">
                            {donations.map((d) => (
                                <tr key={d.id} className="hover:bg-white/5 transition-colors">
                                    <td className="p-4">
                                        <div className="font-mono text-xs text-white/80 mb-1">{d.id.slice(0, 12)}...</div>
                                        <div className="text-white/40 text-xs">{new Date(d.createdAt).toLocaleString()}</div>
                                    </td>
                                    <td className="p-4">
                                        <div className="font-medium text-white">{d.user?.name || "Anonymous Donor"}</div>
                                        <div className="text-white/50 text-xs">{d.user?.email || "No email on record"}</div>
                                    </td>
                                    <td className="p-4">
                                        <div className="flex items-center gap-2">
                                            <span className={`px-2 py-0.5 text-[10px] font-bold uppercase rounded-md ${d.type === "RECURRING_MONTHLY" ? "bg-purple-500/20 text-purple-400" : "bg-white/10 text-white/60"
                                                }`}>
                                                {d.type === "RECURRING_MONTHLY" ? "Sponsorship" : "One-Time"}
                                            </span>
                                        </div>
                                        <div className="mt-1 text-white/70 text-xs">
                                            {d.program?.name || "General Ledger"}
                                        </div>
                                    </td>
                                    <td className="p-4 text-right font-mono font-bold text-white">
                                        ${(Number(d.amount) / 100).toFixed(2)}
                                    </td>
                                    <td className="p-4 text-center">
                                        <span className={`px-2 py-1 text-[10px] font-bold uppercase rounded-md ${d.status === "SUCCEEDED" ? "bg-emerald-500/20 text-emerald-400" :
                                                d.status === "PENDING" ? "bg-impact-gold/20 text-impact-gold" :
                                                    "bg-red-500/20 text-red-400"
                                            }`}>
                                            {d.status}
                                        </span>
                                    </td>
                                    <td className="p-4 text-center">
                                        <span className={`px-2 py-1 text-[10px] font-bold uppercase rounded-md ${d.allocationStatus === "APPROVED" ? "bg-emerald-500/20 text-emerald-400" :
                                                d.allocationStatus === "AUTOMATED" ? "bg-trust-blue/20 text-trust-blue" :
                                                    "bg-white/10 text-white/60"
                                            }`}>
                                            {d.allocationStatus}
                                        </span>
                                    </td>
                                </tr>
                            ))}

                            {donations.length === 0 && (
                                <tr>
                                    <td colSpan={6} className="p-12 text-center text-white/50 flex flex-col items-center gap-3">
                                        <FileSearch className="w-8 h-8 text-white/20" />
                                        No ledger records matches the current filters.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                {totalPages > 1 && (
                    <div className="p-4 border-t border-white/10 flex items-center justify-between">
                        <p className="text-xs text-white/40">Showing page {page} of {totalPages}</p>
                        <div className="flex items-center gap-2">
                            {page > 1 && (
                                <Link href={`/admin/donations?page=${page - 1}${searchParams.type ? `&type=${searchParams.type}` : ''}${searchParams.status ? `&status=${searchParams.status}` : ''}`} className="px-3 py-1 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-xs font-medium text-white transition-colors">
                                    Previous
                                </Link>
                            )}
                            {page < totalPages && (
                                <Link href={`/admin/donations?page=${page + 1}${searchParams.type ? `&type=${searchParams.type}` : ''}${searchParams.status ? `&status=${searchParams.status}` : ''}`} className="px-3 py-1 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-xs font-medium text-white transition-colors">
                                    Next Page
                                </Link>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

import { prisma } from "@/lib/prisma";
import { Mail, AlertCircle, CheckCircle2, Clock, Ban } from "lucide-react";
import Link from "next/link";
import { redirect } from "next/navigation";

export default async function EmailLogsAdminPage({
    searchParams
}: {
    searchParams: { status?: string; event?: string }
}) {
    // Basic Filtering
    const whereClause: any = {};
    if (searchParams.status && searchParams.status !== "ALL") {
        whereClause.deliveryStatus = searchParams.status;
    }
    if (searchParams.event && searchParams.event !== "ALL") {
        whereClause.eventType = searchParams.event;
    }

    const emailLogs = await (prisma as any).emailLog.findMany({
        where: whereClause,
        orderBy: { createdAt: "desc" },
        include: {
            user: {
                select: { name: true, email: true, emailSuppressed: true }
            }
        },
        take: 100 // Hard limit for safety
    });

    const StatusBadge = ({ status }: { status: any }) => {
        const styles: Record<string, string> = {
            PENDING: "bg-white/10 text-white/60",
            SENT: "bg-green-500/10 text-green-400 border border-green-500/20",
            FAILED: "bg-orange-500/10 text-orange-400 border border-orange-500/20",
            BOUNCED: "bg-red-500/10 text-red-400 border border-red-500/20",
        };
        const icons: Record<string, any> = {
            PENDING: <Clock className="w-3 h-3" />,
            SENT: <CheckCircle2 className="w-3 h-3" />,
            FAILED: <AlertCircle className="w-3 h-3" />,
            BOUNCED: <Ban className="w-3 h-3" />,
        };
        return (
            <span className={`px-2.5 py-1 rounded-full text-xs font-bold inline-flex items-center gap-1.5 ${styles[status]}`}>
                {icons[status]}
                {status}
            </span>
        );
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-white flex items-center gap-3">
                        <Mail className="w-8 h-8 text-trust-blue" />
                        Communication Delivery Logs
                    </h1>
                    <p className="text-white/60 mt-2">Audit trail for all dispatched event-driven communications.</p>
                </div>
            </div>

            {/* Filters */}
            <div className="bg-white/5 border border-white/10 rounded-xl p-4 flex flex-wrap gap-4">
                <div className="flex items-center gap-2">
                    <span className="text-sm text-white/50">Status:</span>
                    <div className="flex gap-2">
                        {["ALL", "SENT", "PENDING", "FAILED", "BOUNCED"].map(status => (
                            <Link
                                key={status}
                                href={`?status=${status}&event=${searchParams.event || 'ALL'}`}
                                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${(searchParams.status === status || (!searchParams.status && status === 'ALL'))
                                    ? 'bg-trust-blue text-white'
                                    : 'bg-white/5 text-white/60 hover:bg-white/10 hover:text-white'
                                    }`}
                            >
                                {status}
                            </Link>
                        ))}
                    </div>
                </div>
            </div>

            {/* Log Table */}
            <div className="bg-white/5 border border-white/10 rounded-xl overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="border-b border-white/10 bg-white/5 text-xs text-white/50 uppercase tracking-widest">
                            <th className="p-4 font-medium">Event & Timestamp</th>
                            <th className="p-4 font-medium">Recipient</th>
                            <th className="p-4 font-medium">Delivery Status</th>
                            <th className="p-4 font-medium">Diagnostics</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-white/5">
                        {emailLogs.length === 0 ? (
                            <tr>
                                <td colSpan={4} className="p-8 text-center text-white/40">No communications found matching criteria.</td>
                            </tr>
                        ) : emailLogs.map((log: any) => (
                            <tr key={log.id} className="hover:bg-white/5 transition-colors">
                                <td className="p-4">
                                    <div className="font-mono text-sm text-white mb-1">{log.eventType}</div>
                                    <div className="text-xs text-white/40">
                                        {new Date(log.createdAt).toLocaleString()}
                                    </div>
                                    <div className="text-[10px] text-white/20 mt-1 font-mono truncate max-w-[200px]" title={log.eventId}>
                                        {log.eventId}
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="font-medium text-white">{log.user?.name || "Unknown"}</div>
                                        {log.user?.emailSuppressed && (
                                            <span className="bg-red-500/20 text-red-400 text-[10px] px-1.5 py-0.5 rounded uppercase font-bold tracking-wider" title="User is suppressed due to bounces">Suppressed</span>
                                        )}
                                    </div>
                                    <div className="text-xs text-white/50">{log.user?.email || "No Email"}</div>
                                    <div className="text-xs text-trust-blue/70 mt-1">{log.recipientType}</div>
                                </td>
                                <td className="p-4">
                                    <StatusBadge status={log.deliveryStatus} />
                                    {log.sentAt && (
                                        <div className="text-xs text-white/40 mt-1">
                                            Sent {new Date(log.sentAt).toLocaleTimeString()}
                                        </div>
                                    )}
                                </td>
                                <td className="p-4">
                                    <div className="text-xs text-white/60 mb-1">
                                        <span className="text-white/40">Template:</span> {log.templateVersion}
                                    </div>
                                    {log.errorMessage ? (
                                        <div className="text-xs text-red-400 font-mono bg-red-500/10 p-2 rounded truncate max-w-[250px]" title={log.errorMessage}>
                                            {log.errorMessage}
                                        </div>
                                    ) : (
                                        <span className="text-xs text-white/20">—</span>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

import { auth } from "@/auth";
import { redirect } from "next/navigation";
import prisma from "@/lib/prisma";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Users, AlertTriangle, Activity, ShieldAlert } from "lucide-react";
import { calculateRetentionSignals } from "@/lib/retentionSignals";

export default async function ImpactIntelligenceDashboard() {
    const session = await auth();
    if (!session?.user || (session.user as any).role !== "ADMIN") {
        redirect("/login");
    }

    // --- High-Risk Students (Recent INTERVENTION_REQUIRED reports) ---
    const highRiskReports = await prisma.progressReport.findMany({
        where: { riskScore: "INTERVENTION_REQUIRED" },
        orderBy: { createdAt: "desc" },
        take: 10,
        include: { registryChild: true }
    });

    // --- Recent Operations Activity (Milestones / Approvals) ---
    const recentMilestones = await prisma.impactMilestone.findMany({
        orderBy: { achievedAt: "desc" },
        take: 5,
        include: { registryChild: true }
    });

    // --- Sponsor Engagement Samples (Proxying the retention signal logic over a few active donors) ---
    // Note: In a true prod reporting environment, this would run as an async materialised view.
    // For this dashboard, we sample 10 recent active donors.
    const sampleDonors = await prisma.user.findMany({
        where: { sponsorships: { some: { status: "ACTIVE" } } },
        take: 10,
        orderBy: { updatedAt: "desc" }
    });

    const donorSignals = await Promise.all(
        sampleDonors.map(async (donor) => {
            const signals = await calculateRetentionSignals(donor.id);
            return {
                name: donor.name || "Unknown Donor",
                email: donor.email,
                classification: signals.classification,
                tenure: signals.sponsorTenureDays
            }
        })
    );

    const coolingOrAtRisk = donorSignals.filter(s => s.classification === "COOLING" || s.classification === "AT_RISK");

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in duration-500">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-heading font-bold text-cinematic-dark mb-2">Impact Intelligence Center</h1>
                    <p className="text-gray-500">Observational tracking for safeguarding interventions and donor retention operations.</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* 1. High Risk Children Pipeline */}
                <Card className="border-red-200 shadow-sm">
                    <CardHeader className="bg-red-50/50 border-b border-red-100">
                        <CardTitle className="flex items-center gap-2 text-red-800">
                            <ShieldAlert className="w-5 h-5" /> Active Critical Interventions
                        </CardTitle>
                        <CardDescription>Children flagged with INTERVENTION_REQUIRED in recent progress reports.</CardDescription>
                    </CardHeader>
                    <CardContent className="pt-6">
                        {highRiskReports.length === 0 ? (
                            <p className="text-sm text-gray-500 italic">No critical interventions flagged recently.</p>
                        ) : (
                            <div className="space-y-4">
                                {highRiskReports.map(report => (
                                    <div key={report.id} className="flex justify-between items-center p-3 border border-red-100 rounded-lg bg-white">
                                        <div>
                                            <p className="font-bold text-cinematic-dark">{report.registryChild.displayName}</p>
                                            <p className="text-xs text-red-600">Period: {report.reportingPeriod}</p>
                                        </div>
                                        <Badge variant="destructive" className="bg-red-100 text-red-700 border-red-200">INTERVENTION REQUIRED</Badge>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* 2. Sponsor Engagement Risk (Sample) */}
                <Card className="border-amber-200 shadow-sm">
                    <CardHeader className="bg-amber-50/50 border-b border-amber-100">
                        <CardTitle className="flex items-center gap-2 text-amber-800">
                            <AlertTriangle className="w-5 h-5" /> Donor At-Risk Radar (Sample)
                        </CardTitle>
                        <CardDescription>Active sponsors showing COOLING or AT_RISK engagement patterns.</CardDescription>
                    </CardHeader>
                    <CardContent className="pt-6">
                        {coolingOrAtRisk.length === 0 ? (
                            <p className="text-sm text-gray-500 italic">No donors in the sampled cohort are showing at-risk signals.</p>
                        ) : (
                            <div className="space-y-4">
                                {coolingOrAtRisk.map((donor, idx) => (
                                    <div key={idx} className="flex justify-between items-center p-3 border border-amber-100 rounded-lg bg-white">
                                        <div>
                                            <p className="font-bold text-cinematic-dark">{donor.name}</p>
                                            <p className="text-xs text-amber-600">Tenure: {donor.tenure} days</p>
                                        </div>
                                        <Badge variant="outline" className={`border-amber-200 bg-amber-50 ${donor.classification === 'AT_RISK' ? 'text-red-600' : 'text-amber-700'}`}>
                                            {donor.classification.replace('_', ' ')}
                                        </Badge>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>

                {/* 3. Recent Milestones Pipeline */}
                <Card className="border-blue-200 shadow-sm lg:col-span-2">
                    <CardHeader className="bg-blue-50/50 border-b border-blue-100">
                        <CardTitle className="flex items-center gap-2 text-blue-800">
                            <Activity className="w-5 h-5" /> Recent Impact Events
                        </CardTitle>
                        <CardDescription>Safeguarding-approved milestones generating impact narrative emails.</CardDescription>
                    </CardHeader>
                    <CardContent className="pt-6">
                        {recentMilestones.length === 0 ? (
                            <p className="text-sm text-gray-500 italic">No recent milestones logged.</p>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {recentMilestones.map(milestone => (
                                    <div key={milestone.id} className="p-4 border border-blue-100 rounded-xl bg-white shadow-sm flex flex-col justify-between">
                                        <div>
                                            <span className="text-xs font-bold text-trust-blue uppercase tracking-widest">{milestone.milestoneType.replace(/_/g, " ")}</span>
                                            <p className="font-bold text-cinematic-dark mt-1">{milestone.registryChild.displayName}</p>
                                            <p className="text-xs text-gray-500 mt-2 line-clamp-2">{milestone.description}</p>
                                        </div>
                                        <div className="mt-4 pt-3 border-t border-gray-100 text-[10px] text-gray-400">
                                            {new Date(milestone.achievedAt).toLocaleDateString()}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </CardContent>
                </Card>
            </div>

            <p className="text-center text-xs text-gray-400 mt-12! uppercase tracking-widest">
                Observational Data Only &bull; Protected under Safeguarding Governance Layer
            </p>
        </div>
    );
}

'use client';

import { useState, useTransition } from "react";
import { Search, ChevronDown, ChevronUp, CheckCircle2, Clock, Archive, Trash2, RefreshCw } from "lucide-react";
import { updateInquiryStatus, archiveInquiry, softDeleteInquiry } from "./actions";

type Inquiry = {
    id: string;
    name: string;
    email: string;
    inquiryType: string;
    message: string;
    status: string;
    createdAt: Date;
};

const TYPE_LABELS: Record<string, string> = {
    GENERAL: "General",
    SPONSORSHIP: "Sponsorship",
    REFER_CHILD: "Refer a Child",
    REQUEST_ASSISTANCE: "Assistance",
    PARTNERSHIP: "Partnership",
    MEDIA: "Media",
};

const STATUS_COLORS: Record<string, string> = {
    NEW: "bg-trust-blue/20 text-trust-blue",
    IN_PROGRESS: "bg-impact-gold/20 text-impact-gold",
    RESOLVED: "bg-emerald-500/20 text-emerald-400",
    ARCHIVED: "bg-white/10 text-white/40",
};

export function InquiriesClient({ inquiries }: { inquiries: Inquiry[] }) {
    const [search, setSearch] = useState("");
    const [filterStatus, setFilterStatus] = useState("ALL");
    const [filterType, setFilterType] = useState("ALL");
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [isPending, startTransition] = useTransition();

    const filtered = inquiries.filter(i => {
        const matchSearch = !search || i.name.toLowerCase().includes(search.toLowerCase()) || i.email.toLowerCase().includes(search.toLowerCase());
        const matchStatus = filterStatus === "ALL" || i.status === filterStatus;
        const matchType = filterType === "ALL" || i.inquiryType === filterType;
        return matchSearch && matchStatus && matchType;
    });

    const handleStatusChange = (id: string, newStatus: "IN_PROGRESS" | "RESOLVED") => {
        startTransition(() => updateInquiryStatus(id, newStatus));
    };
    const handleArchive = (id: string) => {
        startTransition(() => archiveInquiry(id));
    };
    const handleDelete = (id: string) => {
        if (!confirm("Permanently soft-delete this inquiry? It will no longer appear in the default view.")) return;
        startTransition(() => softDeleteInquiry(id));
    };

    return (
        <div className="space-y-5">
            {/* Filters */}
            <div className="bg-white/5 border border-white/10 rounded-2xl p-4 flex flex-col md:flex-row gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40" />
                    <input
                        type="text"
                        placeholder="Search by name or email…"
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                        className="w-full pl-9 pr-4 py-2.5 bg-white/5 border border-white/10 rounded-xl text-white text-sm placeholder-white/30 focus:outline-none focus:border-trust-blue"
                    />
                </div>
                <select
                    value={filterStatus}
                    onChange={e => setFilterStatus(e.target.value)}
                    className="px-4 py-2.5 bg-cinematic-dark border border-white/10 rounded-xl text-white text-sm focus:outline-none focus:border-trust-blue"
                >
                    <option value="ALL">All Statuses</option>
                    <option value="NEW">New</option>
                    <option value="IN_PROGRESS">In Progress</option>
                    <option value="RESOLVED">Resolved</option>
                </select>
                <select
                    value={filterType}
                    onChange={e => setFilterType(e.target.value)}
                    className="px-4 py-2.5 bg-cinematic-dark border border-white/10 rounded-xl text-white text-sm focus:outline-none focus:border-trust-blue"
                >
                    <option value="ALL">All Types</option>
                    {Object.entries(TYPE_LABELS).map(([v, l]) => (
                        <option key={v} value={v}>{l}</option>
                    ))}
                </select>
            </div>

            {/* Summary */}
            <p className="text-white/40 text-xs font-medium px-1">
                Showing {filtered.length} of {inquiries.length} inquiries
            </p>

            {/* Table */}
            {filtered.length === 0 ? (
                <div className="text-center py-16 border border-dashed border-white/10 rounded-2xl text-white/30">
                    No inquiries match your filters.
                </div>
            ) : (
                <div className="space-y-3">
                    {filtered.map(inq => {
                        const isExpanded = expandedId === inq.id;
                        return (
                            <div key={inq.id} className="bg-white/5 border border-white/10 rounded-2xl overflow-hidden">
                                {/* Row */}
                                <div className="flex items-start gap-4 p-4">
                                    <div className="flex-1 min-w-0 grid grid-cols-1 md:grid-cols-4 gap-2 md:gap-4">
                                        <div>
                                            <p className="font-bold text-white text-sm truncate">{inq.name}</p>
                                            <p className="text-white/40 text-xs truncate">{inq.email}</p>
                                        </div>
                                        <div>
                                            <span className="text-xs bg-white/10 text-white/60 px-2 py-0.5 rounded-full font-medium">
                                                {TYPE_LABELS[inq.inquiryType] ?? inq.inquiryType}
                                            </span>
                                        </div>
                                        <div>
                                            <span className={`text-xs px-2 py-0.5 rounded-full font-bold ${STATUS_COLORS[inq.status] ?? "bg-white/10 text-white/40"}`}>
                                                {inq.status.replace("_", " ")}
                                            </span>
                                        </div>
                                        <div>
                                            <p className="text-white/40 text-xs">{new Date(inq.createdAt).toLocaleDateString("en-US", { day: "numeric", month: "short", year: "numeric" })}</p>
                                        </div>
                                    </div>

                                    {/* Action buttons */}
                                    <div className="flex items-center gap-1 flex-shrink-0">
                                        <button
                                            onClick={() => setExpandedId(isExpanded ? null : inq.id)}
                                            className="p-1.5 rounded-lg hover:bg-white/10 text-white/50 hover:text-white transition-colors"
                                            title={isExpanded ? "Collapse" : "View message"}
                                        >
                                            {isExpanded ? <ChevronUp className="w-4 h-4" /> : <ChevronDown className="w-4 h-4" />}
                                        </button>

                                        {inq.status === "NEW" && (
                                            <button
                                                onClick={() => handleStatusChange(inq.id, "IN_PROGRESS")}
                                                disabled={isPending}
                                                className="p-1.5 rounded-lg hover:bg-trust-blue/20 text-white/50 hover:text-trust-blue transition-colors"
                                                title="Mark In Progress"
                                            >
                                                <RefreshCw className="w-4 h-4" />
                                            </button>
                                        )}

                                        {inq.status !== "RESOLVED" && (
                                            <button
                                                onClick={() => handleStatusChange(inq.id, "RESOLVED")}
                                                disabled={isPending}
                                                className="p-1.5 rounded-lg hover:bg-emerald-500/20 text-white/50 hover:text-emerald-400 transition-colors"
                                                title="Mark Resolved"
                                            >
                                                <CheckCircle2 className="w-4 h-4" />
                                            </button>
                                        )}

                                        <button
                                            onClick={() => handleArchive(inq.id)}
                                            disabled={isPending}
                                            className="p-1.5 rounded-lg hover:bg-white/10 text-white/50 hover:text-impact-gold transition-colors"
                                            title="Archive"
                                        >
                                            <Archive className="w-4 h-4" />
                                        </button>

                                        <button
                                            onClick={() => handleDelete(inq.id)}
                                            disabled={isPending}
                                            className="p-1.5 rounded-lg hover:bg-red-500/20 text-white/50 hover:text-red-400 transition-colors"
                                            title="Soft Delete"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>

                                {/* Expanded message */}
                                {isExpanded && (
                                    <div className="border-t border-white/10 px-4 py-4 bg-white/[0.02]">
                                        <p className="text-xs text-white/40 font-bold uppercase tracking-widest mb-2">Full Message</p>
                                        <p className="text-white/80 text-sm whitespace-pre-wrap leading-relaxed">{inq.message}</p>
                                        <a
                                            href={`mailto:${inq.email}?subject=Re: Your ${TYPE_LABELS[inq.inquiryType] ?? "Inquiry"} — OneDollarOneChild`}
                                            className="inline-flex items-center gap-1.5 mt-4 text-xs text-trust-blue hover:underline font-medium"
                                        >
                                            Reply to {inq.email} →
                                        </a>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

"use server";

import { auth } from "@/auth";
import prisma from "@/lib/prisma";
import { revalidatePath } from "next/cache";

async function requireAdmin() {
    const session = await auth();
    if (!session?.user || (session.user as any).role !== "ADMIN") {
        throw new Error("Unauthorized");
    }
    return session.user as any;
}

export async function updateInquiryStatus(inquiryId: string, newStatus: "IN_PROGRESS" | "RESOLVED") {
    const user = await requireAdmin();

    // Get previous status for audit log
    const rows = await prisma.$queryRaw<{ status: string }[]>`
        SELECT status FROM "ContactInquiry" WHERE id = ${inquiryId} AND "deletedAt" IS NULL AND "isArchived" = false
    `;
    if (!rows.length) throw new Error("Inquiry not found");
    const previousStatus = rows[0].status;

    await prisma.$executeRaw`
        UPDATE "ContactInquiry"
        SET status = ${newStatus}::"InquiryStatus", "updatedAt" = NOW()
        WHERE id = ${inquiryId}
    `;

    await prisma.$executeRaw`
        INSERT INTO "AdminActionLog" (id, "adminId", "actionType", "targetEntity", "targetId", "previousValue", "newValue", timestamp)
        VALUES (gen_random_uuid()::text, ${user.id}, 'UPDATE_INQUIRY_STATUS', 'ContactInquiry', ${inquiryId}, ${previousStatus}, ${newStatus})
    `;

    revalidatePath("/admin/inquiries");
}

export async function archiveInquiry(inquiryId: string) {
    const user = await requireAdmin();

    await prisma.$executeRaw`
        UPDATE "ContactInquiry"
        SET "isArchived" = true, status = 'ARCHIVED'::"InquiryStatus", "updatedAt" = NOW()
        WHERE id = ${inquiryId}
    `;

    await prisma.$executeRaw`
        INSERT INTO "AdminActionLog" (id, "adminId", "actionType", "targetEntity", "targetId", "previousValue", "newValue", timestamp)
        VALUES (gen_random_uuid()::text, ${user.id}, 'ARCHIVE_INQUIRY', 'ContactInquiry', ${inquiryId}, 'active', 'archived')
    `;

    revalidatePath("/admin/inquiries");
}

export async function softDeleteInquiry(inquiryId: string) {
    const user = await requireAdmin();

    await prisma.$executeRaw`
        UPDATE "ContactInquiry"
        SET "deletedAt" = NOW(), "updatedAt" = NOW()
        WHERE id = ${inquiryId}
    `;

    await prisma.$executeRaw`
        INSERT INTO "AdminActionLog" (id, "adminId", "actionType", "targetEntity", "targetId", "previousValue", "newValue", timestamp)
        VALUES (gen_random_uuid()::text, ${user.id}, 'SOFT_DELETE_INQUIRY', 'ContactInquiry', ${inquiryId}, 'visible', 'deleted')
    `;

    revalidatePath("/admin/inquiries");
}

