export async function GET(request: Request, { params }: { params: Promise<{ donationId: string }> }) {
    const { donationId } = await params;
    const session = await auth();
    // Security Governance: Only the donor themselves or an ADMIN can view this invoice
    if (!session?.user) {
        return new NextResponse("Unauthorized. Sign in required.", { status: 401 });
    }

    try {
        const donation = await prisma.donation.findUnique({
            where: { id: donationId },
            include: { user: true, program: true }
        });

        if (!donation) {
            return new NextResponse("Donation Ledger Entry Not Found", { status: 404 });
        }

        // Authorization Gateway
        const isAdmin = (session.user as any).role === "ADMIN";
        const isOwner = donation.userId === session.user.id;

        if (!isAdmin && !isOwner) {
            return new NextResponse("Forbidden. Strict access controls enforced on financial records.", { status: 403 });
        }

        // Standardize ID pattern: INV-{YEAR}-{DONATION_ID}
        const year = new Date(donation.createdAt).getFullYear();
        const invoiceId = `INV-${year}-${donation.id.slice(-8).toUpperCase()}`;

        const pdfStream = await renderToStream(<InvoicePDF donation={donation} invoiceId={invoiceId} />);

        // Log this generation if accessed by Admin to ensure strict auditing
        if (isAdmin && !isOwner) {
            await prisma.adminActionLog.create({
                data: {
                    adminId: session.user.id as string,
                    actionType: "GENERATE_INVOICE_PDF",
                    targetEntity: "Donation",
                    targetId: donation.id,
                    newValue: `Accessed secure invoice ${invoiceId}`,
                }
            });
        }

        return new NextResponse(pdfStream as any, {
            headers: {
                "Content-Type": "application/pdf",
                "Content-Disposition": `inline; filename="${invoiceId}.pdf"`
            }
        });
    } catch (error) {
        console.error("PDF Invoice Engine Error:", error);
        return new NextResponse("Internal Server Error generating PDF.", { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';

export async function GET(
    request: Request,
    { params }: { params: Promise<{ id: string }> }
) {
    try {
        const { id } = await params;

        const program = await prisma.program.findUnique({
            where: { id },
            include: {
                snapshots: {
                    orderBy: { createdAt: 'desc' },
                    take: 1
                }
            }
        });

        if (!program) {
            return NextResponse.json({ error: 'Program not found' }, { status: 404 });
        }

        // Aggregate Donations for this program
        const donations = await prisma.donation.findMany({
            where: { programId: id, status: 'SUCCEEDED' },
            select: { amount: true, baseAmountUSD: true, allocationBreakdown: true }
        });

        const totalFunded = donations.reduce((sum, d) => sum + Number(d.amount), 0);
        const totalBaseUSD = donations.reduce((sum, d) => sum + Number(d.baseAmountUSD || d.amount), 0);

        // Aggregate across breakdown
        let tuition = 0;
        let supplies = 0;
        let infrastructure = 0;
        let ops = 0;

        donations.forEach(d => {
            if (d.allocationBreakdown) {
                const breakdown: any = d.allocationBreakdown;
                tuition += breakdown.tuition || 0;
                supplies += breakdown.supplies || 0;
                infrastructure += breakdown.infrastructure || 0;
                ops += breakdown.ops || 0;
            }
        });

        const studentsImpacted = program.snapshots[0]?.studentsImpacted || 0;

        return NextResponse.json({
            programId: program.id,
            name: program.name,
            latestStatus: program.status,
            fundingGoal: Number(program.fundingGoal),
            totalFunded,
            totalBaseUSD,
            studentsImpacted,
            allocationBreakdown: {
                tuition,
                supplies,
                infrastructure,
                ops,
                operationalRatio: totalBaseUSD > 0 ? (ops / totalBaseUSD) * 100 : 0
            },
            locked: program.isLocked
        });

    } catch (error: any) {
        console.error('Transparency API Error:', error);
        return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { translate } from 'bing-translate-api';

export async function POST(req: Request) {
    try {
        const { text, to } = await req.json();

        if (!text || !to) {
            return NextResponse.json({ error: "Missing parameters" }, { status: 400 });
        }

        // Use free Bing Translate API (no key required for this wrapper)
        const res = await translate(text, null, to);
        if (!res) {
            throw new Error("Translation returned undefined");
        }
        return NextResponse.json({ translated: res.translation });
    } catch (e: any) {
        console.error("API Translation Error:", e);
        return NextResponse.json({ error: e.message, translated: "" }, { status: 500 });
    }
}

import { NextResponse } from 'next/server';
import { stripe } from '@/lib/stripe';
import prisma from '@/lib/prisma';
import Stripe from 'stripe';
import { triggerPaymentFailedAlert, triggerSponsorshipEndedAlert } from '@/lib/lifecycleAlerts';

const endpointSecret = process.env.STRIPE_WEBHOOK_SECRET;

export async function POST(req: Request) {
    const payload = await req.text();
    const signature = req.headers.get('stripe-signature');

    if (!signature || !endpointSecret) {
        return NextResponse.json({ error: 'Missing signature or secret' }, { status: 400 });
    }

    let event: Stripe.Event;

    try {
        event = stripe.webhooks.constructEvent(payload, signature, endpointSecret);
    } catch (err: any) {
        console.error(`Webhook signature verification failed:`, err.message);
        return NextResponse.json({ error: err.message }, { status: 400 });
    }

    try {
        switch (event.type) {
            case 'checkout.session.completed': {
                const session = event.data.object as Stripe.Checkout.Session;
                if (session.payment_status === 'paid') {
                    await handleSuccessfulPayment(session);
                }
                break;
            }
            case 'invoice.payment_succeeded': {
                const invoice = event.data.object as Stripe.Invoice;
                if (invoice.billing_reason === 'subscription_cycle') {
                    // Handle renewal
                    await handleSuccessfulSubscriptionPayment(invoice);
                }
                break;
            }
            case 'customer.subscription.updated': {
                const subscription = event.data.object as Stripe.Subscription;
                // Read-only extension: Check for past_due or canceled for lifecycle alerts
                if (subscription.status === 'past_due' || subscription.status === 'unpaid') {
                    const sponsorship = await prisma.sponsorship.findFirst({
                        where: { stripeSubscriptionId: subscription.id, status: 'ACTIVE' }
                    });
                    if (sponsorship) {
                        const assignment = await prisma.sponsorshipAssignment.findFirst({
                            where: { donorId: sponsorship.userId, registryChildId: sponsorship.childId || "" }
                        });
                        if (assignment) {
                            await triggerPaymentFailedAlert(assignment.id, "Stripe subscription marked past_due");
                        }
                    }
                } else if (subscription.status === 'canceled') {
                    const sponsorship = await prisma.sponsorship.findFirst({
                        where: { stripeSubscriptionId: subscription.id }
                    });
                    if (sponsorship) {
                        const assignment = await prisma.sponsorshipAssignment.findFirst({
                            where: { donorId: sponsorship.userId, registryChildId: sponsorship.childId || "" }
                        });
                        if (assignment) {
                            await triggerSponsorshipEndedAlert(assignment.id, "Stripe subscription canceled");

                            // Also pause the assignment
                            await prisma.sponsorshipAssignment.update({
                                where: { id: assignment.id },
                                data: { status: 'PAUSED', endedAt: new Date() }
                            });
                        }
                    }
                }
                break;
            }
            default:
                console.log(`Unhandled event type ${event.type}`);
        }
        return NextResponse.json({ received: true });
    } catch (err: any) {
        console.error('Webhook processing error:', err);

        // [FAILSAFE] Store failed webhook payloads for scheduled retry
        try {
            await (prisma as any).failedWebhook.upsert({
                where: { eventId: event.id },
                update: {
                    error: err.message,
                    retryCount: { increment: 1 },
                    status: 'FAILED'
                },
                create: {
                    eventId: event.id,
                    eventType: event.type,
                    payload: event as any,
                    error: err.message,
                    status: 'FAILED'
                }
            });
        } catch (dbErr) {
            console.error('Critical: Failed to log webhook error to db', dbErr);
        }

        return NextResponse.json({ error: 'Webhook processing error', details: err.message }, { status: 500 });
    }
}

async function handleSuccessfulPayment(session: Stripe.Checkout.Session) {
    const stripePaymentId = session.payment_intent as string || session.id;

    // Idempotency: skip if exists
    const existing = await prisma.donation.findUnique({
        where: { stripePaymentId }
    });
    if (existing) return;

    const metadata = session.metadata || {};
    const programId = metadata.programId;
    const childId = metadata.childId;
    const amountStr = metadata.amount;

    if (!programId || !amountStr) return;

    const amount = parseFloat(amountStr);

    // Get pseudo UserId (in real app, use Auth/Session, but for now fallback to systemic user if no explicit donor)
    let user = await prisma.user.findFirst({ where: { role: 'USER' } });
    if (!user) {
        user = await prisma.user.create({ data: { email: `donor_${session.id}@placeholder.com`, role: 'USER', name: 'Anonymous Donor' } });
    }

    // Generate allocation breakdown mapping
    const allocationBreakdown = {
        tuition: amount * 0.60,
        supplies: amount * 0.20,
        infrastructure: amount * 0.15,
        ops: amount * 0.05
    };

    // [CONCURRENCY HARDENING] & [FINANCIAL LEDGER IMMUTABILITY]
    await prisma.$transaction(async (tx) => {
        // 1. Create Donation (Append-Only Ledger)
        await tx.donation.create({
            data: {
                amount,
                currency: 'USD',
                baseAmountUSD: amount,
                fxRate: 1.0,
                status: 'SUCCEEDED',
                stripePaymentId: stripePaymentId,
                type: session.mode === 'subscription' ? 'RECURRING_MONTHLY' : 'ONE_TIME',
                fundType: 'RESTRICTED',
                allocationStatus: 'AUTOMATED', // Or PENDING_APPROVAL for strict governance
                allocationTag: 'Community Pool',
                allocationBreakdown,
                userId: user!.id,
                programId: programId
            }
        });

        // 2. Atomic Program Funding Update
        // In a real high concurrency environment, you would use raw SQL for a true row lock 
        // e.g., await tx.$executeRaw`SELECT * FROM "Program" WHERE id = ${programId} FOR UPDATE`;
        // but Prisma transaction sequential read/write provides baseline consistency.
        const program = await tx.program.findUnique({ where: { id: programId } });

        if (program) {
            // [ESCROW/WAITLIST ROUTING LOGIC PLACEHOLDER]
            // If program is already locked, these funds are technically overflow.
            // In a production NGO app, we'd route this extra to a "General Fund" or Escrow.

            const newFundingCurrent = Number(program.fundingCurrent) + amount;
            const goal = Number(program.fundingGoal);
            const isFullyFunded = newFundingCurrent >= goal;

            await tx.program.update({
                where: { id: programId },
                data: {
                    fundingCurrent: newFundingCurrent,
                    ...(isFullyFunded ? { status: 'FULLY_FUNDED', isLocked: true } : {})
                }
            });

            // [SNAPSHOT REPORTING] Create append-only financial snapshot
            const d = new Date();
            await tx.programSnapshot.upsert({
                where: {
                    programId_month_year: {
                        programId: programId,
                        month: d.getMonth() + 1,
                        year: d.getFullYear()
                    }
                },
                update: {
                    fundsRaised: { increment: amount }
                },
                create: {
                    programId: programId,
                    month: d.getMonth() + 1,
                    year: d.getFullYear(),
                    fundsRaised: amount,
                    studentsImpacted: 0 // calculated in cron jobs based on operational ratios
                }
            });

            // 3. Create generic Sponsorship link if subscription
            if (session.mode === 'subscription') {
                await tx.sponsorship.create({
                    data: {
                        monthlyAmount: amount,
                        stripeSubscriptionId: session.subscription as string,
                        tier: amount >= 30 ? 'FULL' : 'PARTIAL',
                        userId: user!.id,
                        programId: programId,
                        childId: childId || null,
                    }
                });
            }
        }
    });
}

async function handleSuccessfulSubscriptionPayment(invoice: Stripe.Invoice) {
    const pi = (invoice as any).payment_intent;
    const stripePaymentId = typeof pi === 'string'
        ? pi
        : pi?.id;

    if (!stripePaymentId) return;

    // Idempotency flag
    const existing = await prisma.donation.findUnique({
        where: { stripePaymentId }
    });
    if (existing) return;

    const sub = (invoice as any).subscription;
    const subscriptionId = typeof sub === 'string'
        ? sub
        : sub?.id;

    if (!subscriptionId) return;

    // Retrieve subscription to get metadata
    let subscription;
    try {
        subscription = await stripe.subscriptions.retrieve(subscriptionId);
    } catch (e) {
        console.error("Failed to retrieve subscription:", e);
        return;
    }

    const metadata = subscription.metadata || {};
    const programId = metadata.programId;

    if (!programId) return;

    const amount = invoice.amount_paid / 100;

    // Find User by subscription
    const sponsorship = await prisma.sponsorship.findFirst({
        where: { stripeSubscriptionId: subscriptionId }
    });

    if (!sponsorship) return;

    const allocationBreakdown = {
        tuition: amount * 0.60,
        supplies: amount * 0.20,
        infrastructure: amount * 0.15,
        ops: amount * 0.05
    };

    await prisma.$transaction(async (tx) => {
        // Create Donation record for this cycle
        await tx.donation.create({
            data: {
                amount,
                currency: 'USD',
                baseAmountUSD: amount,
                fxRate: 1.0,
                status: 'SUCCEEDED',
                stripePaymentId: stripePaymentId,
                type: 'RECURRING_MONTHLY',
                fundType: 'RESTRICTED',
                allocationStatus: 'AUTOMATED',
                allocationTag: 'Community Pool Renewal',
                allocationBreakdown,
                userId: sponsorship.userId,
                programId: programId
            }
        });

        // Update Program Funding
        const program = await tx.program.findUnique({ where: { id: programId } });
        if (program) {
            const newFundingCurrent = Number(program.fundingCurrent) + amount;
            const goal = Number(program.fundingGoal);
            const isFullyFunded = newFundingCurrent >= goal;

            await tx.program.update({
                where: { id: programId },
                data: {
                    fundingCurrent: newFundingCurrent,
                    ...(isFullyFunded ? { status: 'FULLY_FUNDED', isLocked: true } : {})
                }
            });

            // [SNAPSHOT REPORTING] 
            const d = new Date();
            await tx.programSnapshot.upsert({
                where: {
                    programId_month_year: {
                        programId: programId,
                        month: d.getMonth() + 1,
                        year: d.getFullYear()
                    }
                },
                update: {
                    fundsRaised: { increment: amount }
                },
                create: {
                    programId: programId,
                    month: d.getMonth() + 1,
                    year: d.getFullYear(),
                    fundsRaised: amount,
                    studentsImpacted: 0
                }
            });
        }
    });
}

'use client'

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { loadStripe } from "@stripe/stripe-js";

// Make sure to call `loadStripe` outside of a component’s render to avoid
// recreating the `Stripe` object on every render.
const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY || '');

export function CheckoutForm({ programId, childId }: { programId: string, childId?: string }) {
    const [amount, setAmount] = useState(30);
    const [frequency, setFrequency] = useState<"monthly" | "yearly" | "one-time" | "daily">("monthly");
    const [tier, setTier] = useState<"daily" | "monthly" | "yearly" | "none">("monthly");
    const [isProcessing, setIsProcessing] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleCheckout = async () => {
        setIsProcessing(true);
        setError(null);
        try {
            const response = await fetch('/api/checkout-session', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ programId, childId, amount, frequency }),
            });

            const data = await response.json();

            if (!response.ok) {
                if (data.code === 'PROGRAM_LOCKED') {
                    // Refresh the page to show locked state
                    window.location.reload();
                    return;
                }
                throw new Error(data.error || 'Failed to initialize checkout');
            }

            // Redirect to Stripe Checkout
            window.location.href = data.url;
        } catch (err: any) {
            console.error(err);
            setError(err.message || 'An error occurred during checkout');
            setIsProcessing(false);
        }
    };

    return (
        <div>
            <h2 className="text-xl font-bold text-cinematic-dark mb-6">Select your contribution</h2>

            <div className="flex gap-2 mb-6 p-1 bg-gray-100 rounded-lg">
                <button
                    onClick={() => { setFrequency('monthly'); setAmount(30); setTier('monthly'); }}
                    className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${frequency === 'monthly' || frequency === 'yearly' || frequency === 'daily' ? 'bg-white text-trust-blue shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    Subscription (Recommended)
                </button>
                <button
                    onClick={() => { setFrequency('one-time'); setTier('none'); }}
                    className={`flex-1 py-2 text-sm font-bold rounded-md transition-all ${frequency === 'one-time' ? 'bg-white text-trust-blue shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
                >
                    One-time
                </button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-6">
                {frequency === 'monthly' || frequency === 'yearly' || frequency === 'daily' ? (
                    <>
                        <button onClick={() => { setAmount(1); setFrequency('daily'); setTier('daily'); }} className={`col-span-1 p-4 border-2 rounded-xl text-center transition-all ${tier === 'daily' ? 'border-trust-blue bg-blue-50/50' : 'border-gray-200 hover:border-gray-300'}`}>
                            <span className="block text-2xl font-bold text-gray-900">$1</span>
                            <span className="text-xs font-bold text-trust-blue">per day</span>
                        </button>
                        <button onClick={() => { setAmount(30); setFrequency('monthly'); setTier('monthly'); }} className={`col-span-1 p-4 border-2 rounded-xl text-center transition-all relative ${tier === 'monthly' ? 'border-trust-blue bg-blue-50/50' : 'border-gray-200 hover:border-gray-300'}`}>
                            <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-impact-gold text-[10px] font-bold px-2 py-0.5 rounded text-cinematic-dark whitespace-nowrap">FULL SPONSOR</div>
                            <span className="block text-2xl font-bold text-gray-900">$30</span>
                            <span className="text-xs text-gray-500">per month</span>
                        </button>
                        <button onClick={() => { setAmount(365); setFrequency('yearly'); setTier('yearly'); }} className={`col-span-2 p-4 border-2 rounded-xl text-center transition-all ${tier === 'yearly' ? 'border-trust-blue bg-blue-50/50' : 'border-gray-200 hover:border-gray-300'}`}>
                            <span className="block text-2xl font-bold text-gray-900">$365</span>
                            <span className="text-xs text-gray-500">per year</span>
                        </button>
                    </>
                ) : (
                    <div className="col-span-2">
                        <label htmlFor="custom-amount" className="block text-sm font-bold text-gray-700 mb-2">Custom Amount</label>
                        <div className="relative">
                            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 font-bold">$</span>
                            <input
                                type="number"
                                id="custom-amount"
                                min="1"
                                value={amount}
                                onChange={(e) => { setAmount(Math.max(1, parseInt(e.target.value) || 0)); setTier('none'); }}
                                className="w-full pl-8 pr-4 py-4 rounded-xl border-2 border-gray-200 focus:border-trust-blue focus:ring-4 focus:ring-trust-blue/10 transition-all font-bold text-lg text-gray-900 outline-none"
                            />
                        </div>
                    </div>
                )}
            </div>

            {error && (
                <div className="p-3 mb-6 bg-red-50 border border-red-200 text-red-600 text-sm rounded-lg">
                    {error}
                </div>
            )}

            <Button
                variant="impact"
                size="lg"
                className="w-full py-6 text-lg hover:scale-[1.02] transition-transform"
                onClick={handleCheckout}
                disabled={isProcessing}
            >
                {isProcessing
                    ? 'Processing Securely...'
                    : tier === 'daily'
                        ? 'Sponsor $1 a Day'
                        : `${frequency === 'monthly' || frequency === 'yearly' ? 'Sponsor' : 'Gift'} $${amount} ${frequency === 'monthly' ? 'Monthly' : frequency === 'yearly' ? 'Yearly' : ''}`
                }
            </Button>

            <p className="text-xs text-center text-gray-400 mt-4">
                By contributing, you agree to our Terms of Service and Privacy Policy. <br /> Donation invoices are issued within 24 hours of successful payment.
            </p>
        </div>
    );
}

