}: {
    searchParams: Promise<{ programId?: string, childId?: string, type?: string }>
}) {
    const { programId, childId, type } = await searchParams;

    let targetProgramId = programId;

    // Handle general donation routing logic fallback
    if (!targetProgramId && type === 'general') {
        const generalFund = await prisma.program.findUnique({
            where: { slug: 'general-fund' }
        });

        if (generalFund) {
            targetProgramId = generalFund.id;
        }
    }

    // Handle direct sponsorship routing fallback
    if (!targetProgramId && type === 'sponsorship') {
        const defaultProgram = await prisma.program.findFirst();
        if (defaultProgram) {
            targetProgramId = defaultProgram.id;
        }
    }

    if (!targetProgramId) {
        return <div className="p-8 text-center text-red-500">Missing Program ID or valid donation type</div>;
    }

    const program = await prisma.program.findUnique({
        where: { id: targetProgramId }
    });

    if (!program) {
        notFound();
    }

    // If sponsoring a specific child, fetch their name and monthly funding data
    let childDisplayName: string | undefined;
    let childMonthlyGoal: number | undefined;
    let childMonthlyFunding: number | undefined;
    if (childId) {
        const registryChild = await prisma.registryChild.findUnique({
            where: { id: childId },
            select: { displayName: true, sponsorshipNeededMonthly: true }
        });
        if (registryChild) {
            childDisplayName = registryChild.displayName;
            childMonthlyGoal = Number(registryChild.sponsorshipNeededMonthly);
            // Sum active monthly donations tied to this child
            const monthlyPledges = await prisma.donation.aggregate({
                where: {
                    status: 'SUCCEEDED',
                    type: 'RECURRING_MONTHLY',
                    // Match via metadata — childId is stored in Stripe metadata, not directly on Donation
                    // Fall back to zero if no direct relation exists
                },
                _sum: { amount: true }
            });
            childMonthlyFunding = 0; // Will be computed when webhook-linked assignments are available
        }
    }

    const fundingCurrent = Number(program.fundingCurrent);
    const fundingGoal = Number(program.fundingGoal);
    const isLocked = program.isLocked || fundingCurrent >= fundingGoal || program.status === 'FULLY_FUNDED';

    return (
        <div className="min-h-screen bg-warm-bg py-24 px-4">
            <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-12">

                {/* Left Side: Payment Form / Waitlist */}
                <div className="lg:col-span-7">
                    <h1 className="text-3xl font-heading font-bold text-cinematic-dark mb-4">Complete Your Support</h1>
                    <p className="text-gray-600 mb-8 leading-relaxed">
                        {childDisplayName
                            ? <>You are sponsoring <strong>{childDisplayName}</strong>'s education and support services.</>
                            : <>You are supporting <strong>{program.name}</strong>.</>}
                        {" "}Select your contribution tier and proceed to the encrypted checkout.
                        <span className="block mt-3 text-sm text-gray-500">
                            Support is allocated toward education, learning materials, and wellbeing services. Donation invoices are issued within 24 hours of successful payment.
                        </span>
                    </p>

                    {isLocked ? (
                        <div className="bg-white p-8 rounded-xl shadow-xl border border-impact-gold text-center relative overflow-hidden">
                            <div className="absolute top-0 right-0 p-4 opacity-5 bg-impact-gold transform translate-x-12 -translate-y-12 rounded-full w-48 h-48 pointer-events-none" />
                            <Lock className="w-12 h-12 text-impact-gold mx-auto mb-4" />
                            <h2 className="text-2xl font-bold text-cinematic-dark mb-2">Program Fully Funded</h2>
                            <p className="text-gray-600 mb-8">
                                Thanks to incredible donors like you, <strong>{program.name}</strong> has reached its funding goal! We are currently not accepting new recurring sponsorships to prevent overfunding.
                            </p>

                            <div className="space-y-4">
                                <Link href="/waitlist" className="block w-full">
                                    <Button variant="impact" size="lg" className="w-full">
                                        Join Waitlist for Openings
                                    </Button>
                                </Link>
                                <Link href="/programs" className="block w-full">
                                    <Button variant="outline" size="lg" className="w-full text-gray-600">
                                        Support Another Child
                                    </Button>
                                </Link>
                            </div>
                        </div>
                    ) : (
                        <div className="bg-white p-8 rounded-xl shadow-2xl border border-gray-100">
                            <CheckoutForm programId={program.id} childId={childId} />
                        </div>
                    )}

                    <div className="mt-8">
                        <TrustBadgeStrip className="!bg-transparent !border-none !py-0 !shadow-none" />
                    </div>
                </div>

                {/* Right Side: Governance & Transparency Panels */}
                <div className="lg:col-span-5 space-y-0">
                    <div className="sticky top-24">
                        <ProgramFundingStatusCard
                            programName={program.name}
                            childName={childDisplayName}
                            currentFunding={childMonthlyGoal !== undefined ? (childMonthlyFunding ?? 0) : fundingCurrent}
                            fundingGoal={childMonthlyGoal ?? fundingGoal}
                        />
                        <AllocationPreviewCard />
                        <AdminVerificationNotice />
                        <PostDonationVisibilityNote />
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Send, CheckCircle2, AlertCircle, ChevronDown } from "lucide-react";
import { Button } from "@/components/ui/button";
import Link from "next/link";

const INQUIRY_TYPES = [
    { value: "GENERAL", label: "General Inquiry" },
    { value: "SPONSORSHIP", label: "Sponsor a Child" },
    { value: "REFER_CHILD", label: "Refer a Child" },
    { value: "REQUEST_ASSISTANCE", label: "Request Assistance" },
    { value: "PARTNERSHIP", label: "Institutional Partnership" },
    { value: "MEDIA", label: "Media & Press" },
];

export function ContactForm() {
    const [form, setForm] = useState({ name: "", email: "", inquiryType: "", message: "" });
    const [status, setStatus] = useState<"idle" | "loading" | "success" | "error">("idle");
    const [errorMsg, setErrorMsg] = useState("");

    const charsLeft = 1000 - form.message.length;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setStatus("loading");
        setErrorMsg("");
        try {
            const res = await fetch("/api/contact", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(form),
            });
            const data = await res.json();
            if (!res.ok) {
                setErrorMsg(data.error ?? "Something went wrong.");
                setStatus("error");
            } else {
                setStatus("success");
            }
        } catch {
            setErrorMsg("Network error. Please try again.");
            setStatus("error");
        }
    };

    if (status === "success") {
        return (
            <div className="text-center py-16 space-y-6">
                <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center mx-auto">
                    <CheckCircle2 className="w-8 h-8 text-emerald-600" />
                </div>
                <div>
                    <h2 className="text-2xl font-heading font-bold text-cinematic-dark mb-2">Message Received</h2>
                    <p className="text-gray-500 max-w-sm mx-auto">
                        Thank you, <strong>{form.name}</strong>. We'll review your inquiry and respond to <strong>{form.email}</strong> within 48–72 hours.
                    </p>
                </div>
                <Link href="/" className="inline-block mt-4">
                    <Button variant="outline" className="text-trust-blue border-trust-blue hover:bg-trust-blue/5">
                        Return to Homepage
                    </Button>
                </Link>
            </div>
        );
    }

    return (
        <form onSubmit={handleSubmit} className="space-y-6">
            {/* Name + Email */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                    <label className="block text-sm font-bold text-gray-700">Full Name <span className="text-red-500">*</span></label>
                    <input
                        type="text"
                        required
                        value={form.name}
                        onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                        placeholder="Your full name"
                        className="w-full px-4 py-3 border border-gray-200 rounded-xl text-cinematic-dark focus:outline-none focus:ring-2 focus:ring-trust-blue focus:border-transparent transition-shadow text-sm"
                    />
                </div>
                <div className="space-y-1.5">
                    <label className="block text-sm font-bold text-gray-700">Email Address <span className="text-red-500">*</span></label>
                    <input
                        type="email"
                        required
                        value={form.email}
                        onChange={e => setForm(f => ({ ...f, email: e.target.value }))}
                        placeholder="you@example.com"
                        className="w-full px-4 py-3 border border-gray-200 rounded-xl text-cinematic-dark focus:outline-none focus:ring-2 focus:ring-trust-blue focus:border-transparent transition-shadow text-sm"
                    />
                </div>
            </div>

            {/* Inquiry Type */}
            <div className="space-y-1.5">
                <label className="block text-sm font-bold text-gray-700">Inquiry Type <span className="text-red-500">*</span></label>
                <div className="relative">
                    <select
                        required
                        value={form.inquiryType}
                        onChange={e => setForm(f => ({ ...f, inquiryType: e.target.value }))}
                        className="w-full appearance-none px-4 py-3 border border-gray-200 rounded-xl text-cinematic-dark focus:outline-none focus:ring-2 focus:ring-trust-blue focus:border-transparent transition-shadow text-sm bg-white pr-10"
                    >
                        <option value="" disabled>Select the nature of your inquiry</option>
                        {INQUIRY_TYPES.map(t => (
                            <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                    </select>
                    <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                </div>
            </div>

            {/* Message */}
            <div className="space-y-1.5">
                <div className="flex justify-between items-center">
                    <label className="block text-sm font-bold text-gray-700">Message <span className="text-red-500">*</span></label>
                    <span className={`text-xs font-medium ${charsLeft < 100 ? "text-red-500" : "text-gray-400"}`}>
                        {charsLeft} characters remaining
                    </span>
                </div>
                <textarea
                    required
                    rows={6}
                    maxLength={1000}
                    value={form.message}
                    onChange={e => setForm(f => ({ ...f, message: e.target.value }))}
                    placeholder="Please describe your inquiry in detail…"
                    className="w-full px-4 py-3 border border-gray-200 rounded-xl text-cinematic-dark focus:outline-none focus:ring-2 focus:ring-trust-blue focus:border-transparent transition-shadow text-sm resize-none"
                />
            </div>

            {/* Error */}
            {status === "error" && (
                <div className="flex items-start gap-3 p-4 bg-red-50 border border-red-200 rounded-xl text-sm text-red-700">
                    <AlertCircle className="w-4 h-4 flex-shrink-0 mt-0.5" />
                    <span>{errorMsg}</span>
                </div>
            )}

            {/* Submit */}
            <Button
                type="submit"
                variant="impact"
                size="lg"
                disabled={status === "loading"}
                className="w-full py-6 text-base font-bold hover:-translate-y-0.5 transition-transform shadow-md"
            >
                {status === "loading" ? (
                    <span className="flex items-center gap-2">
                        <span className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin" />
                        Sending…
                    </span>
                ) : (
                    <span className="flex items-center gap-2">
                        <Send className="w-4 h-4" />
                        Send Message
                    </span>
                )}
            </Button>

            <p className="text-xs text-center text-gray-400">
                We respond within 48–72 hours. No spam, no data sharing.
            </p>
        </form>
    );
}

import { Metadata } from "next";
import { auth } from "@/auth";
import { redirect } from "next/navigation";
import { prisma } from "@/lib/prisma";
import { Building2, FileText, Lock, Globe, CheckCircle2, FileBarChart } from "lucide-react";
import Image from "next/image";

export const metadata: Metadata = {
    title: "Corporate Portal | NGO Impact",
    description: "Secure ESG report access and child sponsorship tracking for corporate partners.",
};

export default async function CorporatePortalPage() {
    const session = await auth();

    // 1. Portal Authentication Security
    if (!session?.user) {
        redirect("/login");
    }

    // Derive Sponsor Identity strictly from session mapping, not URL parameters
    const sponsor = await prisma.corporateSponsor.findUnique({
        where: { userId: session.user.id },
        include: {
            allocations: {
                where: { revokedAt: null },
                include: {
                    registryChild: {
                        select: {
                            id: true,
                            displayName: true,
                            age: true,
                            region: true,
                            educationLevel: true,
                            privacyMode: true,
                            avatarIllustrationUrl: true,
                            // 2. Safeguarding Visibility Enforcement
                            // We explicitly DO NOT fetch `caseNotes` here.
                            // `story` and `status` are permitted based on privacy mode later on.
                            story: true,
                            status: true
                        }
                    }
                }
            },
            impactSnapshots: {
                orderBy: { generatedAt: "desc" }
            }
        }
    }) as any;

    if (!sponsor) {
        // Not a mapped corporate partner user
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center max-w-md mx-auto">
                <Lock className="w-16 h-16 text-white/20 mb-6" />
                <h1 className="text-2xl font-heading font-bold text-white mb-2">Access Restricted</h1>
                <p className="text-white/60">
                    Your account is not currently linked to an active Corporate Partnership. If you believe this is an error, please contact your account manager.
                </p>
