import prisma from "@/lib/prisma";
import { getFundingGapReport } from "./fundingEngine";

export interface SponsorshipAnalytics {
    cancellationRate: number; // Percentage 0-100
    avgSponsorshipDurationDays: number;
    fundingStabilityIndex: number; // Percentage 0-100 indicating how "stable" the sponsorships are
    graceRecoveryRate: number;
    priorityQueueSize: number;
    criticalChildrenCount: number;
    avgSponsorSlotsFilled: number;
    // Phase 9: CSR Specific Metrics
    corporateFundingShare: number;
    corporateRetentionDuration: number;
    // Phase 11: Internationalization Metrics
    donorRegionDistribution: Record<string, number>;
    corporateRegionDistribution: Record<string, number>;
    fundingByCurrencyDisplay: Record<string, number>;
    localeEngagementBreakdown: Record<string, number>;
}

/**
 * Calculates high-level aggregate analytics for sponsorship health.
 * NOTE: Designed to NOT track sensitive financial details (sums, transaction amounts).
 * Purely structural lifecycle analytics.
 */
export async function generateSponsorshipAnalytics(): Promise<SponsorshipAnalytics> {
    // 1. Sponsorship Cancellation Rate (Churn Rate)
    // Formula: (Cancelled Sponsorships / Total Ever Active Sponsorships) * 100
    const allAssignments = await prisma.sponsorshipAssignment.findMany({
        select: {
            status: true,
            startedAt: true,
            endedAt: true
        }
    });

    const totalEverActive = allAssignments.length;
    const totalEnded = allAssignments.filter(a => a.status === "ENDED" || a.status === "PAUSED").length;

    const cancellationRate = totalEverActive === 0 ? 0 : (totalEnded / totalEverActive) * 100;

    // 2. Average Sponsorship Duration
    // Calculate for ended sponsorships, or use (now - start) for active ones
    let totalDurationDays = 0;
    allAssignments.forEach(a => {
        const end = a.endedAt ? new Date(a.endedAt) : new Date();
        const start = new Date(a.startedAt);
        const diffTime = Math.abs(end.getTime() - start.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        totalDurationDays += diffDays;
    });

    const avgSponsorshipDurationDays = totalEverActive === 0 ? 0 : totalDurationDays / totalEverActive;

    // 3. Funding Stability Index
    // Formula: (Total Fully Sponsored Slots / Total Needed Slots across active children) * 100
    // Modified by recent Payment Failures (penalty)
    const gapReport = await getFundingGapReport();

    const activeChildren = gapReport.all;
    let totalNeededSlots = 0;
    let totalFilledSlots = 0;

    activeChildren.forEach(child => {
        totalNeededSlots += child.maxSponsors;
        totalFilledSlots += child.activeSponsors;
    });

    let baseStability = totalNeededSlots === 0 ? 100 : (totalFilledSlots / totalNeededSlots) * 100;

    // Apply a penalty to stability for recent AT_RISK or PAYMENT_FAILED health logs
    const recentFails = await prisma.sponsorshipHealthLog.count({
        where: {
            healthStatus: { in: ["PAYMENT_FAILED", "AT_RISK"] },
            createdAt: { gte: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000) }
        }
    });

    // 1% penalty per active failure log in the last 30 days, capped at 20%
    const penalty = Math.min(20, recentFails * 1);
    const fundingStabilityIndex = Math.max(0, baseStability - penalty);

    const priorityQueueSize = await prisma.sponsorshipPriorityQueue.count({ where: { resolvedAt: null } });

    const avgSponsorSlotsFilled = activeChildren.length === 0 ? 0 : parseFloat((totalFilledSlots / activeChildren.length).toFixed(1));

    const criticalChildrenCount = gapReport.critical.length;

    // Grace Recovery Rate (Placeholder until successful payment webhooks log HEALTHY)
    const graceRecoveryRate = 0;

    // PHASE 9: CSR Metrics calculation
    const corporateAllocations = await (prisma as any).corporateSponsorshipAllocation.findMany({
        select: {
            filledSlots: true,
            createdAt: true,
            revokedAt: true,
        }
    });

    const activeCorporateSlots = corporateAllocations
        .filter((a: any) => !a.revokedAt)
        .reduce((sum: number, current: any) => sum + current.filledSlots, 0);

    const corporateFundingShare = totalFilledSlots === 0 ? 0 : (activeCorporateSlots / totalFilledSlots) * 100;

    let totalCorporateDuration = 0;
    corporateAllocations.forEach((a: any) => {
        const end = a.revokedAt ? new Date(a.revokedAt) : new Date();
        const start = new Date(a.createdAt);
        totalCorporateDuration += Math.ceil(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
    });

    const corporateRetentionDuration = corporateAllocations.length === 0 ? 0 : totalCorporateDuration / corporateAllocations.length;

    // PHASE 11: Geo Analytics
    const users = await prisma.user.findMany({ where: { role: 'USER' } });
    const donorRegionDistribution: Record<string, number> = {};
    const fundingByCurrencyDisplay: Record<string, number> = {};
    const localeEngagementBreakdown: Record<string, number> = {};

    users.forEach((u: any) => {
        if (u.regionCode) donorRegionDistribution[u.regionCode] = (donorRegionDistribution[u.regionCode] || 0) + 1;
        fundingByCurrencyDisplay[u.preferredCurrency] = (fundingByCurrencyDisplay[u.preferredCurrency] || 0) + 1;
        localeEngagementBreakdown[u.preferredLocale] = (localeEngagementBreakdown[u.preferredLocale] || 0) + 1;
    });

    const corporateSponsors = await prisma.corporateSponsor.findMany({ include: { user: true } });
    const corporateRegionDistribution: Record<string, number> = {};
    corporateSponsors.forEach(c => {
        if (c.user?.regionCode) {
            corporateRegionDistribution[c.user.regionCode] = (corporateRegionDistribution[c.user.regionCode] || 0) + 1;
        }
    });

    return {
        cancellationRate: parseFloat(cancellationRate.toFixed(2)),
        avgSponsorshipDurationDays: Math.round(avgSponsorshipDurationDays),
        fundingStabilityIndex: parseFloat(fundingStabilityIndex.toFixed(2)),
        graceRecoveryRate,
        priorityQueueSize,
        criticalChildrenCount,
        avgSponsorSlotsFilled,
        corporateFundingShare: parseFloat(corporateFundingShare.toFixed(2)),
        corporateRetentionDuration: Math.round(corporateRetentionDuration),
        donorRegionDistribution,
        corporateRegionDistribution,
        fundingByCurrencyDisplay,
        localeEngagementBreakdown
    };
}

/**
 * Super lightweight tracking layer for Impact + Retention events.
 * 10% sampling rule is enforced to prevent performance overhead on the DB.
 */
export async function trackImpactEvent(eventType: "EMAIL_OPENED" | "DASHBOARD_NARRATIVE_VIEWED" | "MILESTONE_CLICKED", donorId: string, childId?: string) {
    // 10% sampling rule - only ingest 1 out of 10 events directly to DB. 
    // The rest would theoretically go to a faster timeseries DB or simply be discarded for performance.
    if (Math.random() > 0.10) {
        return;
    }

    try {
        await prisma.adminActionLog.create({
            data: {
                adminId: donorId, // Using admin action log as a generic event sink for this system
                actionType: "UPDATE_IMPACT_METRIC",
                targetEntity: "CHILD",
                targetId: childId || "SYS",
                previousValue: "N/A",
                newValue: `[IMPACT_ANALYTICS] Type: ${eventType}`
            }
        });
        console.log(`[Analytics] Tracked ${eventType} for Donor ${donorId}`);
    } catch (e) {
        // Silently fail to not blow up runtime
        console.error("[Analytics] Failed to track event", e);
    }
}

import { prisma } from "@/lib/prisma";
import { User } from "next-auth";

/**
 * PHASE 9 - CORPORATE ALLOCATION ENGINE
 * Validates available sponsorship capacity across individual and corporate sponsors.
 * Maps RegistryChildren to CorporateSponsors without mutating Donation ledgers.
 */
export async function allocateChildrenToCorporateSponsor(sponsorId: string, admin: User) {
    // 1. Fetch Corporate Sponsor and their current allocations
    const sponsor = await prisma.corporateSponsor.findUnique({
        where: { id: sponsorId },
        include: {
            allocations: true,
        },
    });

    if (!sponsor) throw new Error("Corporate Sponsor not found.");
    if (sponsor.status !== "ACTIVE") throw new Error("Cannot allocate children to inactive sponsors.");

    const currentFilledSlots = sponsor.allocations.filter(a => !a.revokedAt).length;
    const remainingCapacity = sponsor.sponsorshipCapacity - currentFilledSlots;

    if (remainingCapacity <= 0) {
        return { success: false, error: "Sponsor has reached maximum capacity." };
    }

    // 2. Identify eligible children based on Co-Funding Governance Rule
    // totalCorporateSlots + totalIndividualSlots < maxSponsors

    // Fetch all children not fully sponsored, prioritized by deepest funding gap / WAITING status
    const eligibleChildrenRaw = await prisma.registryChild.findMany({
        where: {
            status: { in: ["WAITING", "PARTIALLY_FUNDED"] as any },
            isArchived: false,
            deletedAt: null,
        },
        include: {
            assignments: { where: { status: "ACTIVE" } } as any,
            corporateAllocations: { where: { revokedAt: null } }
        },
        orderBy: [
            { status: "asc" }, // WAITING first
            { age: "asc" }     // Then youngest
        ]
    });

    // 3. Filter strictly by Co-Funding Rule mapping capacity limits
    const eligibleChildren = eligibleChildrenRaw.filter(child => {
        // Prevent double mapping to the same corporate sponsor
        const alreadyAllocated = (child as any).corporateAllocations.some((a: any) => a.corporateSponsorId === sponsorId);
        if (alreadyAllocated) return false;

        const totalIndividualSlots = (child as any).assignments.length;
        const totalCorporateSlots = (child as any).corporateAllocations.reduce((acc: any, curr: any) => acc + curr.allocatedSlots, 0);

        return (totalIndividualSlots + totalCorporateSlots) < child.maxSponsors;
    });

    if (eligibleChildren.length === 0) {
        return { success: false, error: "No eligible children available for allocation under current capacity rules." };
    }

    // 4. Determine how many to allocate this batch
    const allocationCount = Math.min(remainingCapacity, eligibleChildren.length);
    const childrenToAllocate = eligibleChildren.slice(0, allocationCount);

    const newAllocations = [];

    // 5. Execute Relational Mapping (Strictly Isolated from Donation/Stripe tables)
    for (const child of childrenToAllocate) {
        const allocation = await prisma.corporateSponsorshipAllocation.create({
            data: {
                corporateSponsorId: sponsorId,
                registryChildId: child.id,
                allocatedSlots: 1, // Standardizing to 1 slot per child per sponsor for mapping
                filledSlots: 1,
                allocationStatus: "FULLY_ALLOCATED"
            }
        });
        newAllocations.push(allocation);

        // Update child status to PARTIALLY_FUNDED if they were waiting 
        // We do NOT mark them fully funded here because funding logic stays purely in the Donation webhook tier.
        if (child.status === "WAITING") {
            await prisma.registryChild.update({
                where: { id: child.id },
                data: { status: "PARTIALLY_FUNDED" as any }
            });
        }
    }

    // 6. Audit Logging Required by Governance
    await prisma.adminActionLog.create({
        data: {
            adminId: admin.id!,
            actionType: "BULK_ALLOCATE",
            targetEntity: "CorporateSponsor",
            targetId: sponsorId,
            newValue: JSON.stringify({
                allocatedCount: newAllocations.length,
                childIds: newAllocations.map(a => a.registryChildId)
            }),
        }
    });

    return {
        success: true,
        allocatedCount: newAllocations.length,
        allocations: newAllocations
    };
}

/**
 * Handle Reversal Governance for a specific allocation
 */
export async function revokeCorporateAllocation(allocationId: string, reason: string, admin: User) {
    const allocation = await prisma.corporateSponsorshipAllocation.update({
        where: { id: allocationId },
        data: {
            revokedAt: new Date(),
            revokedReason: reason,
            allocationStatus: "OPEN"
        }
    });

    // Audit Logging
    await prisma.adminActionLog.create({
        data: {
            adminId: admin.id!,
            actionType: "REVOKE_ALLOCATION",
            targetEntity: "CorporateSponsorshipAllocation",
            targetId: allocationId,
            newValue: JSON.stringify({ reason }),
        }
    });

    return { success: true, allocation };
}

import { prisma } from "./prisma";
import { dispatchEmailEvent } from "./email/emailEventBus";

/**
 * PHASE 9.7 - CORPORATE RETENTION SIGNALS
 * Separate from individual donor retention logic, this tracks Corporate specific
 * engagement metrics like contract duration, renewal windows, and fulfillment.
 */

export async function checkCorporateRenewalReadiness(sponsorId: string) {
    const sponsor = await (prisma as any).corporateSponsor.findUnique({
        where: { id: sponsorId },
        include: { allocations: { where: { revokedAt: null } } }
    });

    if (!sponsor || !sponsor.contractEndDate) return null;

    const daysUntilExpiry = Math.ceil((sponsor.contractEndDate.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));

    // Fulfillment velocity
    const fulfillmentRate = sponsor.sponsorshipCapacity > 0
        ? sponsor.allocations.length / sponsor.sponsorshipCapacity
        : 0;

    const renewalWindowOpen = daysUntilExpiry <= 90; // 90-day renewal cycle for enterprise

    // Phase 10 Integration: Dispatch automated alerts if triggered appropriately
    if (daysUntilExpiry === 60) {
        await dispatchEmailEvent({
            eventType: "CONTRACT_EXPIRY_WARNING",
            recipientId: sponsor.userId!,
            recipientType: "CORPORATE",
            entityId: sponsor.id,
            isCritical: true, // Warnings are flagged as critical
            data: { organizationName: sponsor.organizationName }
        });
    } else if (daysUntilExpiry === 90) {
        await dispatchEmailEvent({
            eventType: "CORPORATE_RENEWAL_WINDOW",
            recipientId: sponsor.userId!,
            recipientType: "CORPORATE",
            entityId: sponsor.id,
            data: { organizationName: sponsor.organizationName }
        });
    }

    return {
        sponsorId,
        daysUntilExpiry,
        renewalWindowOpen,
        fulfillmentRate, // e.g. 0.8 = 80% capacity filled
        healthScore: calculateHealthScore(fulfillmentRate, daysUntilExpiry)
    };
}

function calculateHealthScore(fulfillmentRate: number, daysToExpiry: number) {
    let score = 100;
    if (fulfillmentRate < 0.5) score -= 30; // Poor utilization
    if (daysToExpiry < 30 && fulfillmentRate < 0.8) score -= 20; // Expiring soon, not fully engaged
    return score;
}

import { prisma } from "../prisma";
import { SupportedCurrency, SupportedLocale } from "@prisma/client";

/**
 * PHASE 11 - CURRENCY DISPLAY ABSTRACTION
 * 
 * Strict Governance Rules:
 * 1. Accepts ledger values in USD only
 * 2. Performs conversion strictly for UI rendering
 * 3. Never persists converted values in database
 * 4. Never overrides Donation, Sponsorship, or CSRImpactSnapshot amounts
 */
export async function convertDisplayAmount(amountUSD: number | any, targetCurrency: SupportedCurrency, locale: SupportedLocale = "EN"): Promise<string> {
    const numericAmount = typeof amountUSD === 'object' && amountUSD.toNumber ? amountUSD.toNumber() : Number(amountUSD);

    // 1. Base Currency Short-Circuit Format
    if (targetCurrency === "USD") {
        return new Intl.NumberFormat(getLocaleString(locale), { style: "currency", currency: "USD" }).format(numericAmount);
    }

    // 2. Fetch Latest Snapshot
    const snapshot = await (prisma as any).exchangeRateSnapshot.findFirst({
        where: {
            baseCurrency: "USD",
            targetCurrency: targetCurrency
        },
        orderBy: {
            capturedAt: "desc"
        }
    });

    // 3. Fallback to base USD on missing snapshot
    if (!snapshot) {
        console.warn(`[CURRENCY_TRANSLATOR] Missing snapshot for USD -> ${targetCurrency}. Falling back to USD display.`);
        return new Intl.NumberFormat(getLocaleString(locale), { style: "currency", currency: "USD" }).format(numericAmount);
    }

    // 4. Transform strictly for display scalar logic
    const convertedAmount = numericAmount * snapshot.rate;

    return new Intl.NumberFormat(getLocaleString(locale), { style: "currency", currency: targetCurrency }).format(convertedAmount);
}

function getLocaleString(locale: SupportedLocale): string {
    switch (locale) {
        case "FR": return "fr-FR";
        case "ES": return "es-ES";
        case "HI": return "hi-IN";
        case "EN":
        default: return "en-US";
    }
}

import { prisma } from "../prisma";
import { EmailEventType, RecipientType } from "@prisma/client";
import { emailQueue } from "../queue/queueClient";
import { logger } from "../logger";

export interface BatchInstruction {
    eventType: EmailEventType;
    recipientType: RecipientType;
    recipients: { recipientId: string, entityId: string, data: any }[];
    isCritical?: boolean;
}

export async function processEmailBatch(instruction: BatchInstruction) {
    const { recipients, eventType, recipientType, isCritical } = instruction;

    // 1. Backpressure Protection
    // Check pending queue length before ingestion
    const pendingCount = await prisma.emailLog.count({
        where: { deliveryStatus: "PENDING" }
    });

    if (pendingCount > 500) {
        logger.error({ pendingCount, eventType }, `[BATCH_PROCESSOR] Backpressure active. Pausing ingestion.`);
        // Phase 12: In a real system, ops would be alerted via DLQ/Sentry
        return false;
    }

    // 2. Batch Chunking (Max 50 per execution cycle)
    const CHUNK_SIZE = 50;
    const chunks = [];

    for (let i = 0; i < recipients.length; i += CHUNK_SIZE) {
        chunks.push(recipients.slice(i, i + CHUNK_SIZE));
    }

    logger.info({ total: recipients.length, chunks: chunks.length, eventType }, `[BATCH_PROCESSOR] Ingesting emails into BullMQ.`);

    for (const [index, chunk] of chunks.entries()) {
        const jobs = chunk.map(r => {
            const eventId = `${eventType}-${r.recipientId}-${r.entityId}`;
            return {
                name: `BatchEmail-${eventId}`,
                data: {
                    eventType,
                    recipientId: r.recipientId,
                    recipientType,
                    entityId: r.entityId,
                    data: r.data,
                    isCritical
                },
                opts: {
                    jobId: eventId // Base Deduplication
                }
            };
        });

        // Add chunk to Redis in massive parallel bulk transaction
        await emailQueue.addBulk(jobs);

        // 3. Optional buffer between chunks during ingestion
        if (index < chunks.length - 1) {
            await new Promise(resolve => setTimeout(resolve, 1000));
        }
    }

    logger.info({ eventType }, `[BATCH_PROCESSOR] Finished bulk enqueueing.`);
    return true;
}

import { prisma } from "../prisma";
import { DeliveryStatus, RecipientType, EmailEventType } from "@prisma/client";

interface EmailPayload {
    to: string;
    subject: string;
    html: string;
    eventId: string;
    recipientId: string;
    recipientType: RecipientType;
    eventType: EmailEventType;
    templateVersion: string;
}

export async function sendEmailWithTracking(payload: EmailPayload) {
    // 1. Create PENDING Log
    const log = await prisma.emailLog.create({
        data: {
            eventId: payload.eventId,
            recipientId: payload.recipientId,
            recipientType: payload.recipientType,
            eventType: payload.eventType,
            templateVersion: payload.templateVersion,
            deliveryStatus: "PENDING"
        }
    });

    try {
        // Mock email transport (would be nodemailer, resend, etc.)
        // Simulate a success or failure
        const isSuccess = Math.random() > 0.05; // 95% success rate for simulation

        if (!isSuccess) {
            throw new Error("Simulated SMTP Transport Failure");
        }

        // 2. Mark SENT
        await prisma.emailLog.update({
            where: { id: log.id },
            data: {
                deliveryStatus: "SENT",
                sentAt: new Date()
            }
        });

    } catch (error: any) {
        // 3. Mark FAILED or BOUNCED
        // For simulation, let's say 20% of errors are soft FAILS (can retry), 80% are BOUNCES (hard fail)
        const isBounce = Math.random() > 0.2;
        const newStatus = isBounce ? "BOUNCED" : "FAILED";

        await prisma.emailLog.update({
            where: { id: log.id },
            data: {
                deliveryStatus: newStatus,
                errorMessage: error.message
            }
        });

        // 4. Implement Bounce Suppression Policy
        if (newStatus === "BOUNCED") {
            const bounceCount = await prisma.emailLog.count({
                where: {
                    recipientId: payload.recipientId,
                    deliveryStatus: "BOUNCED"
                }
            });

            if (bounceCount > 3) {
                await prisma.user.update({
                    where: { id: payload.recipientId },
                    data: { emailSuppressed: true }
                });
                console.warn(`[EMAIL_CLIENT] Suppressed User ${payload.recipientId} due to >3 bounces.`);
            }
        }

        throw error; // Rethrow for the EventBus to handle retries if applicable
    }
}

import { prisma } from "../prisma";
import { EmailEventType, RecipientType } from "@prisma/client";
import { TemplateRegistry } from "./templateRegistry";
import { calculateDispatchDelay } from "../scheduling/timezoneDispatcher";
import { emailQueue } from "../queue/queueClient";
import { logger } from "../logger";

interface DispatchPayload {
    eventType: EmailEventType;
    recipientId: string;
    recipientType: RecipientType;
    entityId: string; // Used for idempotency mapping (e.g. childId, reportId)
    data: any; // Dynamic data for the template
    isCritical?: boolean;
}

export async function dispatchEmailEvent(payload: DispatchPayload) {
    // We now await the ingestion to guarantee it hits Redis before Http Returns
    try {
        // 1. Check User Suppressed Status
        const user = await prisma.user.findUnique({
            where: { id: payload.recipientId },
            include: { emailPreferences: true }
        });

        if (!user) return;
        if (user.emailSuppressed && !payload.isCritical) {
            logger.info({ recipientId: payload.recipientId, eventType: payload.eventType }, `[EVENT_BUS] Skipping email - User Suppressed`);
            return;
        }

        // 2. Check User Preferences
        const prefs = user.emailPreferences;
        if (prefs && !payload.isCritical) {
            if (payload.eventType === "REPORT_VERIFIED" && !prefs.receiveImpactUpdates) return;
            if (payload.eventType === "MILESTONE_LOGGED" && !prefs.receiveMilestones) return;
            if (payload.eventType === "CSR_SNAPSHOT_READY" && !prefs.receiveCSRReports) return;
        }

        // 3. Idempotency Check
        const eventId = `${payload.eventType}-${payload.recipientId}-${payload.entityId}`;
        const existingLog = await prisma.emailLog.findUnique({
            where: { eventId }
        });

        if (existingLog) {
            logger.info({ eventId }, `[EVENT_BUS] Idempotency blocked duplicate.`);
            return;
        }

        // 4. Event Throttling Governance (48 hours per eventType per user)
        if (!payload.isCritical) {
            const recentLog = await prisma.emailLog.findFirst({
                where: {
                    recipientId: payload.recipientId,
                    eventType: payload.eventType,
                    createdAt: { gte: new Date(Date.now() - 48 * 60 * 60 * 1000) }
                }
            });

            if (recentLog) {
                logger.warn({ eventId }, `[EVENT_BUS] Throttled duplicate dispatch. Sent within last 48h.`);
                return;
            }
        }

        // 5. Template Resolution
        const template = TemplateRegistry.getTemplate(payload.eventType, user.preferredLocale);
        if (!template) {
            logger.error({ eventType: payload.eventType }, "Template not found for EventType");
            return;
        }

        const subject = template.subject(payload.data);
        const html = template.html(payload.data);

        // 6. Timezone Aware Scheduling Delay
        const delayMs = payload.isCritical ? 0 : calculateDispatchDelay(user.timezone);

        // 7. Enqueue persistent background job
        // REVIEW RULE: Idempotency parameter is passed as Job ID
        try {
            await emailQueue.add(
                `SendEmail-${eventId}`,
                {
                    to: user.email,
                    subject,
                    html,
                    eventId,
                    recipientId: payload.recipientId,
                    recipientType: payload.recipientType,
                    eventType: payload.eventType,
                    templateVersion: template.version
                },
                {
                    jobId: eventId, // Enforces Redis-level deduplication
                    delay: delayMs
                }
            );

            logger.info({ eventId, delayMs }, `[EVENT_BUS] Successfully enqueued email payload.`);
        } catch (error: any) {
            logger.error({ eventId, error: error.message }, `[EVENT_BUS] Failed to enqueue email job.`);
        }
    } catch (error: any) {
        logger.error({ error: error.message, eventType: payload.eventType }, `[EVENT_BUS] Critical dispatch failure.`);
    }
}

