        // Fallback sequentially to EN if template is missing in target locale
        const localeDict = LOCALES[locale] || LOCALES["EN"];
        const template = localeDict[eventType] || EN_TEMPLATES[eventType];

        const version = "v1.1-localized"; // Consistent versioning across locales

        return {
            version,
            subject: (data: any) => template.subject(data),
            html: (data: any) => {
                const bodyHtml = template.html(data);

                // REVIEW RULE: Safeguarding footer must be appended AFTER translation
                const footerHtml = getSafeguardingFooter(locale);
                return `${bodyHtml}\n${footerHtml}`;
            }
        };
    }
};

import prisma from "@/lib/prisma";
import { unstable_cache } from "next/cache";

export type FundingStatus = "STABLE" | "AT_RISK" | "HIGH_RISK" | "CRITICAL";

export interface ChildFundingSummary {
    childId: string;
    name: string;
    region: string;
    activeSponsors: number;
    maxSponsors: number;
    remainingSlots: number;
    status: FundingStatus;
    fullySponsored: boolean;
    gracePeriodSponsors: number;
}

/**
 * Funding Stability Logic is derived operational intelligence.
 * No financial ledger mutations occur within this system.
 * All classifications are observational and reversible.
 */

const GRACE_PERIOD_MS = 14 * 24 * 60 * 60 * 1000; // 14 days

export const calculateFundingStatus = unstable_cache(
    async (childId: string): Promise<ChildFundingSummary> => {
        const child = await prisma.registryChild.findUnique({
            where: { id: childId },
            include: {
                assignments: {
                    where: { status: "ACTIVE" }
                }
            }
        });

        if (!child) throw new Error("RegistryChild not found");

        const activeAssignmentIds = child.assignments.map(a => a.id);
        const logs = await prisma.sponsorshipHealthLog.findMany({
            where: { sponsorshipId: { in: activeAssignmentIds } },
            orderBy: { createdAt: "desc" }
        });

        const now = new Date().getTime();
        let validActiveCount = 0;
        let gracePeriodCount = 0;

        for (const a of child.assignments) {
            const latestLog = logs.find(l => l.sponsorshipId === a.id);
            if (latestLog && latestLog.healthStatus === "PAYMENT_FAILED") {
                const timeSince = now - new Date(latestLog.createdAt).getTime();
                if (timeSince > GRACE_PERIOD_MS) {
                    continue; // Grace period expired, doesn't count as active slot
                } else {
                    gracePeriodCount++;
                }
            }
            validActiveCount++;
        }

        const activeSponsors = validActiveCount;
        const remainingSlots = Math.max(0, child.maxSponsors - activeSponsors);
        const fundingRatio = child.maxSponsors > 0 ? activeSponsors / child.maxSponsors : 1;

        let status: FundingStatus = "STABLE";
        if (fundingRatio === 0) status = "CRITICAL";
        else if (fundingRatio < 0.5) status = "HIGH_RISK";
        else if (fundingRatio < 1) status = "AT_RISK";

        return {
            childId: child.id,
            name: child.displayName,
            region: child.region,
            activeSponsors,
            maxSponsors: child.maxSponsors,
            remainingSlots,
            status,
            fullySponsored: remainingSlots === 0,
            gracePeriodSponsors: gracePeriodCount
        };
    },
    ["calculate-funding-status"],
    { revalidate: 900, tags: ["funding-engine"] }
);

export const getFundingGapReport = unstable_cache(
    async () => {
        const activeChildren = await prisma.registryChild.findMany({
            where: {
                deletedAt: null,
                isArchived: false,
                status: { in: ["WAITING", "SPONSORED"] }
            },
            include: {
                assignments: {
                    where: { status: "ACTIVE" },
                    include: { donor: true }
                }
            },
            orderBy: { createdAt: "desc" }
        });

        const activeAssignmentIds = activeChildren.flatMap(c => c.assignments.map(a => a.id));
        const logs = await prisma.sponsorshipHealthLog.findMany({
            where: { sponsorshipId: { in: activeAssignmentIds } },
            orderBy: { createdAt: "desc" }
        });

        const now = new Date().getTime();
        const gracePeriodDetails: any[] = []; // Collect active grace period sponsors for Admin Dashboard

        const report: ChildFundingSummary[] = activeChildren.map(child => {
            let validActiveCount = 0;
            let gracePeriodCount = 0;

            for (const a of child.assignments) {
                const latestLog = logs.find(l => l.sponsorshipId === a.id);
                if (latestLog && latestLog.healthStatus === "PAYMENT_FAILED") {
                    const timeSince = now - new Date(latestLog.createdAt).getTime();
                    if (timeSince > GRACE_PERIOD_MS) {
                        continue;
                    } else {
                        gracePeriodCount++;
                        gracePeriodDetails.push({
                            sponsorshipId: a.id,
                            donorName: a.donor.name || "Unknown Donor",
                            childName: child.displayName,
                            graceUntil: new Date(new Date(latestLog.createdAt).getTime() + GRACE_PERIOD_MS)
                        });
                    }
                }
                validActiveCount++;
            }

            const activeSponsors = validActiveCount;
            const remainingSlots = Math.max(0, child.maxSponsors - activeSponsors);
            const fundingRatio = child.maxSponsors > 0 ? activeSponsors / child.maxSponsors : 1;

            let status: FundingStatus = "STABLE";
            if (fundingRatio === 0) status = "CRITICAL";
            else if (fundingRatio < 0.5) status = "HIGH_RISK";
            else if (fundingRatio < 1) status = "AT_RISK";

            return {
                childId: child.id,
                name: child.displayName,
                region: child.region,
                activeSponsors,
                maxSponsors: child.maxSponsors,
                remainingSlots,
                status,
                fullySponsored: remainingSlots === 0,
                gracePeriodSponsors: gracePeriodCount
            };
        });

        return {
            critical: report.filter(r => r.status === "CRITICAL"),
            highRisk: report.filter(r => r.status === "HIGH_RISK"),
            atRisk: report.filter(r => r.status === "AT_RISK"),
            stable: report.filter(r => r.status === "STABLE"),
            all: report,
            totalGapCount: report.reduce((sum, r) => sum + r.remainingSlots, 0),
            gracePeriodDetails
        };
    },
    ["funding-gap-report"],
    { revalidate: 900, tags: ["funding-engine"] }
);

import prisma from "@/lib/prisma";
import { unstable_cache } from "next/cache";
import { GoogleGenAI } from "@google/genai";

// Initialize AI safely
let ai: GoogleGenAI | null = null;
try {
    if (process.env.GEMINI_API_KEY) {
        ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });
    }
} catch (error) {
    console.warn("[ImpactNarrativeEngine] Failed to initialize GoogleGenAI. Will use fallback.", error);
}

/**
 * AI Generation with strict cost, length, and prompt governance.
 * Falls back to structured template on failure or missing API key.
 */
async function generateNarrativeFromData(child: any): Promise<string> {
    const report = child.progressReports[0];
    if (!report) return `We are currently gathering the latest progress updates for ${child.displayName}.`;

    const recentMilestone = child.milestones[0];
    const milestoneText = recentMilestone ? ` They also recently achieved a major milestone: ${recentMilestone.milestoneType.replace(/_/g, ' ')}.` : "";

    // Strict Fallback Template (Failure Isolation)
    const fallbackTemplate = `This reporting period, ${child.displayName} has shown dedicated effort in their education. Their academic performance is noted as: "${report.academicPerformance}". ${report.attendanceRate ? `Their attendance rate is currently at ${report.attendanceRate}%.` : ""}${milestoneText} Thank you for your continued support in making this progress possible.`;

    if (!ai) {
        return fallbackTemplate;
    }

    const prompt = `
You are a professional, compassionate NGO impact reporter.
Write a progress summary for a sponsored child named ${child.displayName}.

STRICT RESTRAINTS:
1. Max length: 120 words.
2. Tone: Uplifting, neutral, dignity-preserving.
3. Reading level: Grade 6.
4. DO NOT mention or reference any past trauma, abuse, or deeply sensitive wellbeing issues.
5. DO NOT hallucinate facts.
6. DO NOT include identifiable personal details beyond their first name, age (${child.age}), and region (${child.region}).
7. Write as a direct update to their sponsor.

DATA PROVIDED:
- Academic Performance: ${report.academicPerformance}
- Attendance Rate: ${report.attendanceRate ? report.attendanceRate + '%' : 'N/A'}
- Teacher Feedback: ${report.teacherFeedback || 'N/A'}
- Wellbeing Notes: ${report.wellbeingNotes || 'N/A'} (Filter out trauma, focus on positive engagement)
- Recent Milestone: ${recentMilestone ? recentMilestone.milestoneType.replace(/_/g, ' ') + ' - ' + recentMilestone.description : 'None'}
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                maxOutputTokens: 400,
                temperature: 0.4,
            }
        });

        if (!response.text) throw new Error("Empty AI response");
        return response.text.trim();
    } catch (error) {
        console.error("[ImpactNarrativeEngine] AI Generation Failed, using fallback. Error:", error);
        return fallbackTemplate;
    }
}

/**
 * Cached entry point for the summary engine.
 * Tagged for invalidation when a report is verified or a milestone is logged.
 */
export async function getChildImpactSummary(childId: string): Promise<string> {
    const fetchAndGenerate = unstable_cache(
        async (id: string) => {
            const child = await prisma.registryChild.findUnique({
                where: { id },
                include: {
                    progressReports: {
                        where: { verificationStatus: "VERIFIED" },
                        orderBy: { createdAt: "desc" },
                        take: 1
                    },
                    milestones: {
                        orderBy: { achievedAt: "desc" },
                        take: 1
                    }
                }
            });

            if (!child) return "Sponsorship details are currently being processed.";

            return generateNarrativeFromData(child);
        },
        [`impact-summary-${childId}`],
        {
            revalidate: 86400, // 24 hours
            tags: [`child-${childId}-impact`]
        }
    );

    return fetchAndGenerate(childId);
}

import { prisma } from "../prisma";
import { logger } from "../logger";
import { dispatchEmailEvent } from "../email/emailEventBus";

/**
 * PHASE 12: DATA INTEGRITY CRON JOBS
 * 
 * REVIEW RULE: Read-Only Audit Enforcement
 * strictly read-only. It may log anomalies & dispatch admin alerts.
 * Must NOT mutate sponsorship records or ExchangeRateSnapshots.
 */

export async function runDailyAudit() {
    logger.info("[AUDIT] Starting Daily Ledger & Infrastructure Audit.");
    const anomalies: string[] = [];

    try {
        // 1. Check maxSponsors capacity limits (Total Active Donors + Corporate Slots > Max Sponsors)
        const children = await prisma.registryChild.findMany({
            include: {
                assignments: { where: { status: "ACTIVE" } },
                corporateAllocations: { where: { revokedAt: null } }
            }
        });

        for (const child of children) {
            const totalSponsors = child.assignments.length + child.corporateAllocations.length;
            if (totalSponsors > child.maxSponsors) {
                anomalies.push(`CAPACITY_BREACH: Child ${child.id} has ${totalSponsors} sponsors (Max: ${child.maxSponsors})`);
            }
        }

        // 2. Orphaned Corporate Allocations
        const orphanedAllocations = await prisma.corporateSponsorshipAllocation.findMany({
            where: {
                corporateSponsorId: null as any // Bypass strict typescript null coercion to query DB null states
            }
        });

        if (orphanedAllocations.length > 0) {
            anomalies.push(`ORPHANED_ALLOCATIONS: Found ${orphanedAllocations.length} allocations missing a CorporateSponsor link.`);
        }

        // 3. EmailLog records missing EventType (Audit trail break)
        // Checking for any eventType that doesn't match a valid known enum if possible,
        // or just logging any parsing failures natively. Prisma's ENUM type `EmailEventType`
        // inherently protects against `null` insertion at the DB level via `NOT NULL` constraints
        // We will execute a raw query to check for legacy mismatched rows.
        const brokenLogs: any[] = await prisma.$queryRaw`SELECT count(*) FROM "EmailLog" WHERE "eventType"::text IS NULL OR "eventType"::text = ''`;

        const count = Number(brokenLogs[0]?.count || 0);

        if (count > 0) {
            anomalies.push(`BROKEN_AUDIT_LOG: Found ${count} EmailLogs missing 'eventType'.`);
        }

        // 4. ExchangeRateSnapshot Gaps
        // Note: Using aggregate because `exchangeRateSnapshot` is an append-only ledger on `prisma.$queryRaw`
        const recentSnapshotRes: any[] = await prisma.$queryRaw`SELECT MAX("createdAt") as "latest" FROM "ExchangeRateSnapshot"`;
        const latestTime = recentSnapshotRes[0]?.latest;

        let hasGap = true;
        if (latestTime) {
            const timeDiff = Date.now() - new Date(latestTime).getTime();
            if (timeDiff < 48 * 60 * 60 * 1000) {
                hasGap = false;
            }
        }

        if (hasGap) {
            anomalies.push(`STALE_EXCHANGE_RATES: No ExchangeRateSnapshot found within the last 48 hours.`);
        }

        // Conclusion
        if (anomalies.length > 0) {
            logger.fatal({ anomalies }, "[AUDIT_FAILED] Critical ledger/schema discrepancies found.");

            // Dispatch Alert to System Admin
            const admin = await prisma.user.findFirst({ where: { role: "ADMIN" } });
            if (admin) {
                await dispatchEmailEvent({
                    eventType: "RISK_SCORE_CHANGED", // Repurposing critical alerts template
                    recipientId: admin.id,
                    recipientType: "ADMIN",
                    entityId: "DAILY_AUDIT",
                    data: {
                        childName: "SYSTEM AUDIT",
                        narrative: `Daily Audit found anomalies: \n${anomalies.join("\n")}`,
                        oldScore: "PASS",
                        newScore: "FAIL"
                    },
                    isCritical: true
                });
            }
        } else {
            logger.info("[AUDIT_PASS] All 4 daily audit checks passed cleanly.");
        }

    } catch (error: any) {
        logger.error({ error: error.message }, "[AUDIT_CRASH] Failed to complete daily audit.");
    }
}

import pino from "pino";

/**
 * PHASE 12: STRUCTURED LOGGING LAYER
 * 
 * REVIEW RULE: Log Integrity & Tamper Protection
 * Production logs must:
 * - Be write-only and unmodifiable.
 * - Be exported sequentially as JSON for downstream consumption (e.g. Datadog / Vercel Logs).
 * - NOT contain naked PII (redaction layer enforced implicitly by avoiding raw user object dumps).
 */

const isProduction = process.env.NODE_ENV === "production";

// Pino configuration
export const logger = pino({
    level: process.env.LOG_LEVEL || "info",
    // In development, use pino-pretty for readable console output.
    // In production, emit raw JSON for ingestion.
    ...(isProduction
        ? {}
        : {
            transport: {
                target: "pino-pretty",
                options: {
                    colorize: true,
                    translateTime: "HH:MM:ss Z",
                    ignore: "pid,hostname",
                },
            },
        }),
});

// Helper for consistent error logging
export const logError = (context: string, error: unknown, metadata?: Record<string, any>) => {
    let errMessage = "Unknown error";
    let stack: string | undefined;

    if (error instanceof Error) {
        errMessage = error.message;
        stack = error.stack;
    } else if (typeof error === 'string') {
        errMessage = error;
    } else {
        errMessage = JSON.stringify(error);
    }

    logger.error({
        context,
        errMessage,
        stack,
        ...metadata
    }, `[${context}] Error: ${errMessage}`);
};

import { Queue, QueueOptions, Worker, WorkerOptions, Job } from "bullmq";
import Redis from "ioredis";
import { logger } from "../logger";

/**
 * PHASE 12: PERSISTENT JOB QUEUE
 * 
 * Replaces inherently fragile `setTimeout` logic with persistent Redis-backed BullMQ logic.
 */

// We enforce a local Redis instance for dev, or a managed URI for prod
const redisUrl = process.env.REDIS_URL || "redis://localhost:6379";
export const redisConnection = new Redis(redisUrl, {
    maxRetriesPerRequest: null,
});

redisConnection.on('error', (err) => {
    logger.error({ err }, '[REDIS] Connection Error. Verify redis-server is running.');
});

// Default shared options applying User Governance Constraints
const DEFAULT_QUEUE_OPTIONS: QueueOptions = {
    connection: redisConnection as any, // Bypass strict ioredis internal typing mismatch in BullMQ
    defaultJobOptions: {
        attempts: 3,                 // REVIEW RULE: All jobs must enforce retry policy
        backoff: {
            type: 'exponential',
            delay: 5000              // 5s, 25s, 125s
        },
        removeOnComplete: true,      // Keep DB clean
        removeOnFail: false          // REVIEW RULE: DLQ Policy - Failed jobs must NOT silently disappear. They stay in Redis for Admin UI visibility.
    }
};

// 1. Instantiate Queues
export const emailQueue = new Queue("emailQueue", DEFAULT_QUEUE_OPTIONS);
export const impactNarrativeQueue = new Queue("impactNarrativeQueue", DEFAULT_QUEUE_OPTIONS);
export const csrReportQueue = new Queue("csrReportQueue", DEFAULT_QUEUE_OPTIONS);
export const lifecycleAlertQueue = new Queue("lifecycleAlertQueue", DEFAULT_QUEUE_OPTIONS);

/**
 * Helper to gracefully start a worker while binding global error monitoring.
 */
export function createWorker<T>(
    queueName: string,
    processor: (job: Job<T>) => Promise<any>,
    options?: Partial<WorkerOptions>
): Worker {

    const worker = new Worker(queueName, processor, {
        connection: redisConnection as any, // Bypass strict ioredis typing
        concurrency: 5,
        ...options
    });

    worker.on("completed", (job) => {
        logger.info({ jobId: job.id, name: job.name }, `[QUEUE] ${queueName} job completed successfully.`);
    });

    // REVIEW RULE: Dead Letter Queue (DLQ) Policy implementation
    // If a job exhausts all attempts, it naturally triggers "failed" iteratively until max attempts.
    // At max attempts, BullMQ moves it to 'failed' state in Redis which acts as our DLQ, viewable via Bull Board.
    worker.on("failed", (job, err) => {
        if (job) {
            const hasExhaustedRetries = job.attemptsMade >= (job.opts.attempts || 1);

            if (hasExhaustedRetries) {
                // DLQ Trigger
                logger.fatal({
                    jobId: job.id,
                    name: job.name,
                    errMessage: err.message
                }, `[DLQ_ALERT] ${queueName} job critically failed after max retries. Moved to Dead Letter state.`);
            } else {
                logger.warn({
                    jobId: job.id,
                    name: job.name,
                    attempt: job.attemptsMade,
                    errMessage: err.message
                }, `[QUEUE_RETRY] ${queueName} job failed. Retrying...`);
            }
        } else {
            logger.error({ errMessage: err.message }, `[QUEUE] Worker error on ${queueName}`);
        }
    });

    return worker;
}

import { prisma } from "../prisma";
import { getChildImpactSummary } from "../impactNarrativeEngine";
import { dispatchEmailEvent } from "../email/emailEventBus";
import { impactNarrativeQueue } from "../queue/queueClient";
import { logger } from "../logger";

/**
 * Event map for the Background Queue
 */
export type QueueEvent =
    | { type: "REPORT_VERIFIED", childId: string }
    | { type: "MILESTONE_LOGGED", childId: string, milestoneType: string }
    | { type: "RISK_SCORE_CHANGED", childId: string, oldScore: string, newScore: string };

/**
 * Queue Resilience Strategy: Push to robust Redis-backed BullMQ logic. 
 * Prevents in-memory loss during rapid Vercel container rotation.
 */
export async function dispatchImpactEvent(event: QueueEvent) {
    // REVIEW RULE: Idempotency metric provided to queue
    const jobId = `${event.type}-${event.childId}-${Date.now()}`;

    try {
        await impactNarrativeQueue.add(
            `ProcessImpact-${event.type}`,
            event,
            { jobId } // Built-in enqueue deduplication based on exact timestamp grouping
        );
        logger.info({ jobId, eventType: event.type }, `[ImpactQueue] Enqueued impact generation event.`);
    } catch (error: any) {
        logger.error({ error: error.message, eventType: event.type }, `[ImpactQueue] Failed to enqueue event.`);
    }
}

// NOTE: This logic is heavily synchronous. In Phase 12, this is moved to be processed BY THE WORKER
// See `src/lib/queue/queueClient.ts` workers.
export async function processImpactEvent(event: QueueEvent) {
    logger.info({ childId: event.childId }, `[ImpactQueue] Processing ${event.type}`);

    // Fetch the child + their assignments to find sponsors to notify
    const child = await (prisma as any).registryChild.findUnique({
        where: { id: event.childId },
        include: {
            assignments: {
                where: { status: "ACTIVE" },
                include: { donor: true }
            },
            corporateAllocations: {
                where: { revokedAt: null },
                include: { corporateSponsor: true }
            }
        }
    });

    if (!child) throw new Error("Child not found for event");
    if (child.assignments.length === 0 && child.corporateAllocations.length === 0) {
        logger.info({ childId: child.id }, `[ImpactQueue] No active sponsors found. Skipping dispatch.`);
        return;
    }

    // Generate the AI summary (safely cached and fallback-protected by the engine)
    const aiSummary = await getChildImpactSummary(child.id);

    // Fetch the latest active report for attendance info
    const latestReport = await prisma.progressReport.findFirst({
        where: { registryChildId: child.id, verificationStatus: "VERIFIED" },
        orderBy: { createdAt: "desc" }
    });

    const attendanceStr = latestReport?.attendanceRate !== null ? `${latestReport?.attendanceRate}%` : "Not available";

    // Build a flattened array of all recipients
    const recipients: { id: string; type: "DONOR" | "CORPORATE" }[] = [];
    child.assignments.forEach((a: any) => recipients.push({ id: a.donor.id, type: "DONOR" }));
    child.corporateAllocations.forEach((a: any) => {
        if (a.corporateSponsor?.userId) {
            recipients.push({ id: a.corporateSponsor.userId, type: "CORPORATE" });
        }
    });

    // Dispatch emails to all active sponsors
    const dispatchPromises = recipients.map(async (recipient) => {
        switch (event.type) {
            case "REPORT_VERIFIED":
                await dispatchEmailEvent({
                    eventType: "REPORT_VERIFIED",
                    recipientId: recipient.id,
                    recipientType: recipient.type,
                    entityId: event.childId,
                    data: { childName: child.displayName, narrative: aiSummary }
                });
                break;
            case "MILESTONE_LOGGED":
                await dispatchEmailEvent({
                    eventType: "MILESTONE_LOGGED",
                    recipientId: recipient.id,
                    recipientType: recipient.type,
                    entityId: event.childId,
                    data: { childName: child.displayName, milestoneTitle: event.milestoneType }
                });
                break;
            case "RISK_SCORE_CHANGED":
                await dispatchEmailEvent({
                    eventType: "RISK_SCORE_CHANGED",
                    recipientId: recipient.id,
                    recipientType: recipient.type,
                    entityId: event.childId,
                    isCritical: true,
                    data: { childName: child.displayName }
                });
                break;
        }
    });

    await Promise.all(dispatchPromises);
}

/**
 * PHASE 11: TIMEZONE-AWARE SCHEDULING
 * 
 * Known Limitation:
 * Current timezone-based dispatch uses in-memory delay logic.
 * Delayed jobs will not survive server restarts. Suitable for moderate traffic only.
 * Future Enhancement (Phase 12): Migrate to Redis-backed delayed job queue (e.g., BullMQ)
 * to persist scheduled events safely across restarts.
 */
export function calculateDispatchDelay(timezone: string | null): number {
    if (!timezone) return 0; // Immediate if no timezone set

    try {
        // Get the current hour in the target timezone
        const options: Intl.DateTimeFormatOptions = {
            timeZone: timezone,
            hour: 'numeric',
            hour12: false,
        };
        const formatter = new Intl.DateTimeFormat('en-US', options);
        const hourString = formatter.format(new Date());

        // Handle variations where '24' might be returned for midnight
        let currentHour = parseInt(hourString, 10);
        if (currentHour === 24) currentHour = 0;

        // 8 AM to 6 PM is the valid window (8 to 17 inclusively)
        if (currentHour >= 8 && currentHour < 18) {
            return 0; // Immediate dispatch
        }

        // Calculate hours until 8 AM next day
        let hoursToWait = 0;
        if (currentHour < 8) {
            hoursToWait = 8 - currentHour;
        } else {
            hoursToWait = (24 - currentHour) + 8;
        }

        // Return delay in milliseconds
        return hoursToWait * 60 * 60 * 1000;

    } catch (error) {
        console.warn(`[TIMEZONE_DISPATCHER] Invalid timezone '${timezone}'. Defaulting to immediate dispatch.`);
        return 0;
    }
}

